{
  "name": "@node/diet-tracker",
  "version": "1.0.0",
  "description": "Track daily meals, calories, and macronutrient categories with weekly chart visualization",
  "modnet": {
    "contentType": "health",
    "structure": "list",
    "mechanics": ["track", "chart"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type FoodCategory = 'protein' | 'carbs' | 'fat' | 'fiber'

export type FoodItem = {
  name: string
  calories: number
  categories: FoodCategory[]
}

export type Meal = {
  id: string
  name: string
  items: FoodItem[]
  totalCalories: number
  timestamp: string
}

export type DailyGoal = {
  calories: number
}

export type DailySummary = {
  date: string
  meals: Meal[]
  totalCalories: number
  goal: number
}

export type WeeklyData = {
  days: { date: string; totalCalories: number }[]
  goal: number
}

import type { Meal, DailyGoal } from './types'

const DATA_DIR = new URL('./data/', import.meta.url).pathname

const MEALS_PATH = `${DATA_DIR}meals.jsonl`
const GOALS_PATH = `${DATA_DIR}goals.json`

const DEFAULT_GOAL: DailyGoal = { calories: 2000 }

export const readGoal = async (): Promise<DailyGoal> => {
  const file = Bun.file(GOALS_PATH)
  if (!(await file.exists())) return DEFAULT_GOAL
  return file.json()
}

export const writeGoal = async (goal: DailyGoal): Promise<void> => {
  await Bun.write(GOALS_PATH, JSON.stringify(goal, null, 2))
}

export const readMeals = async (): Promise<Meal[]> => {
  const file = Bun.file(MEALS_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text
    .split('\n')
    .filter((line) => line.trim().length > 0)
    .map((line) => JSON.parse(line) as Meal)
}

export const appendMeal = async (meal: Meal): Promise<void> => {
  const file = Bun.file(MEALS_PATH)
  const existing = (await file.exists()) ? await file.text() : ''
  const newLine = JSON.stringify(meal) + '\n'
  await Bun.write(MEALS_PATH, existing + newLine)
}

export const deleteMeal = async (id: string): Promise<boolean> => {
  const meals = await readMeals()
  const filtered = meals.filter((m) => m.id !== id)
  if (filtered.length === meals.length) return false
  const content = filtered.map((m) => JSON.stringify(m)).join('\n') + (filtered.length > 0 ? '\n' : '')
  await Bun.write(MEALS_PATH, content)
  return true
}

import type { FoodItem, Meal, DailySummary, WeeklyData } from './types'
import { readMeals, appendMeal, readGoal, writeGoal } from './store'

const generateId = (): string => crypto.randomUUID()

const toDateString = (date: Date): string => date.toISOString().slice(0, 10)

export const logMeal = async (
  name: string,
  items: FoodItem[],
  timestamp?: string
): Promise<Meal> => {
  const meal: Meal = {
    id: generateId(),
    name,
    items,
    totalCalories: items.reduce((sum, item) => sum + item.calories, 0),
    timestamp: timestamp ?? new Date().toISOString(),
  }
  await appendMeal(meal)
  return meal
}

export const getDailySummary = async (date?: string): Promise<DailySummary> => {
  const targetDate = date ?? toDateString(new Date())
  const meals = await readMeals()
  const goal = await readGoal()

  const dayMeals = meals.filter(
    (m) => toDateString(new Date(m.timestamp)) === targetDate
  )

  return {
    date: targetDate,
    meals: dayMeals,
    totalCalories: dayMeals.reduce((sum, m) => sum + m.totalCalories, 0),
    goal: goal.calories,
  }
}

export const getWeeklyData = async (): Promise<WeeklyData> => {
  const meals = await readMeals()
  const goal = await readGoal()
  const today = new Date()
  const days: WeeklyData['days'] = []

  for (let i = 6; i >= 0; i--) {
    const d = new Date(today)
    d.setDate(d.getDate() - i)
    const dateStr = toDateString(d)
    const dayMeals = meals.filter(
      (m) => toDateString(new Date(m.timestamp)) === dateStr
    )
    days.push({
      date: dateStr,
      totalCalories: dayMeals.reduce((sum, m) => sum + m.totalCalories, 0),
    })
  }

  return { days, goal: goal.calories }
}

export const setDailyGoal = async (calories: number): Promise<void> => {
  await writeGoal({ calories })
}

import { h, Fragment } from 'plaited'
import type { DailySummary, WeeklyData, FoodCategory } from './types'

const CATEGORY_COLORS: Record<FoodCategory, string> = {
  protein: '#e74c3c',
  carbs: '#f39c12',
  fat: '#9b59b6',
  fiber: '#2ecc71',
}

const styles = {
  container: {
    fontFamily: 'system-ui, -apple-system, sans-serif',
    maxWidth: '640px',
    margin: '0 auto',
    padding: '16px',
    color: '#1a1a1a',
  },
  heading: {
    fontSize: '24px',
    fontWeight: '700',
    marginBottom: '16px',
  },
  subheading: {
    fontSize: '18px',
    fontWeight: '600',
    marginBottom: '12px',
  },
  card: {
    border: '1px solid #e0e0e0',
    borderRadius: '8px',
    padding: '12px',
    marginBottom: '8px',
    backgroundColor: '#fafafa',
  },
  progressBar: {
    height: '12px',
    borderRadius: '6px',
    backgroundColor: '#e0e0e0',
    overflow: 'hidden',
    marginBottom: '8px',
  },
  tag: {
    display: 'inline-block',
    padding: '2px 8px',
    borderRadius: '12px',
    fontSize: '12px',
    fontWeight: '500',
    color: '#fff',
    marginRight: '4px',
  },
  barRow: {
    display: 'flex',
    alignItems: 'center',
    marginBottom: '6px',
    gap: '8px',
  },
  barLabel: {
    width: '80px',
    fontSize: '13px',
    textAlign: 'right' as const,
    flexShrink: '0',
  },
  barTrack: {
    flex: '1',
    height: '24px',
    backgroundColor: '#e0e0e0',
    borderRadius: '4px',
    overflow: 'hidden',
    position: 'relative' as const,
  },
  barValue: {
    fontSize: '12px',
    width: '60px',
    textAlign: 'right' as const,
    flexShrink: '0',
  },
}

const renderCategoryTag = (category: FoodCategory) =>
  h('span', {
    style: { ...styles.tag, backgroundColor: CATEGORY_COLORS[category] },
  }, category)

export const renderDailySummary = (summary: DailySummary) => {
  const pct = Math.min((summary.totalCalories / summary.goal) * 100, 100)
  const overGoal = summary.totalCalories > summary.goal
  const fillColor = overGoal ? '#e74c3c' : '#3498db'

  return h('div', { style: styles.container },
    h('h1', { style: styles.heading }, `Daily Summary — ${summary.date}`),

    h('div', { style: { marginBottom: '16px' } },
      h('div', { style: { display: 'flex', justifyContent: 'space-between', marginBottom: '4px' } },
        h('span', {}, `${summary.totalCalories} kcal consumed`),
        h('span', {}, `Goal: ${summary.goal} kcal`),
      ),
      h('div', { style: styles.progressBar },
        h('div', {
          style: {
            width: `${pct}%`,
            height: '100%',
            backgroundColor: fillColor,
            borderRadius: '6px',
            transition: 'width 0.3s',
          },
        }),
      ),
      overGoal
        ? h('div', { style: { color: '#e74c3c', fontSize: '14px' } },
            `Over goal by ${summary.totalCalories - summary.goal} kcal`)
        : h('div', { style: { color: '#27ae60', fontSize: '14px' } },
            `${summary.goal - summary.totalCalories} kcal remaining`),
    ),

    h('h2', { style: styles.subheading }, 'Meals'),

    summary.meals.length === 0
      ? h('p', { style: { color: '#888' } }, 'No meals logged today.')
      : h(Fragment, {},
          ...summary.meals.map((meal) =>
            h('div', { style: styles.card },
              h('div', { style: { display: 'flex', justifyContent: 'space-between', marginBottom: '4px' } },
                h('strong', {}, meal.name),
                h('span', {}, `${meal.totalCalories} kcal`),
              ),
              h('div', { style: { fontSize: '13px', color: '#555' } },
                new Date(meal.timestamp).toLocaleTimeString(),
              ),
              h('div', { style: { marginTop: '6px' } },
                ...meal.items.map((item) =>
                  h('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '2px 0' } },
                    h('span', { style: { fontSize: '14px' } }, item.name),
                    h('div', { style: { display: 'flex', alignItems: 'center', gap: '6px' } },
                      ...item.categories.map(renderCategoryTag),
                      h('span', { style: { fontSize: '13px', color: '#666' } }, `${item.calories} kcal`),
                    ),
                  ),
                ),
              ),
            ),
          ),
        ),
  )
}

export const renderWeeklyChart = (data: WeeklyData) => {
  const maxCal = Math.max(data.goal, ...data.days.map((d) => d.totalCalories))
  const scale = maxCal > 0 ? 100 / maxCal : 0
  const goalPct = data.goal * scale

  const dayLabels = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

  return h('div', { style: styles.container },
    h('h2', { style: styles.subheading }, 'Weekly Calorie Intake'),

    ...data.days.map((day) => {
      const d = new Date(day.date + 'T00:00:00')
      const label = `${dayLabels[d.getDay()]} ${day.date.slice(5)}`
      const barPct = day.totalCalories * scale
      const overGoal = day.totalCalories > data.goal
      const barColor = overGoal ? '#e74c3c' : '#3498db'

      return h('div', { style: styles.barRow },
        h('div', { style: styles.barLabel }, label),
        h('div', { style: styles.barTrack },
          h('div', {
            style: {
              width: `${barPct}%`,
              height: '100%',
              backgroundColor: barColor,
              borderRadius: '4px',
            },
          }),
          h('div', {
            style: {
              position: 'absolute',
              left: `${goalPct}%`,
              top: '0',
              bottom: '0',
              width: '2px',
              backgroundColor: '#2c3e50',
            },
          }),
        ),
        h('div', { style: styles.barValue }, `${day.totalCalories}`),
      )
    }),

    h('div', { style: { display: 'flex', alignItems: 'center', gap: '8px', marginTop: '8px', fontSize: '13px', color: '#555' } },
      h('div', { style: { width: '16px', height: '2px', backgroundColor: '#2c3e50' } }),
      h('span', {}, `Daily goal: ${data.goal} kcal`),
    ),
  )
}

import { createSSR } from 'plaited'
import type { FoodItem } from './types'
import { logMeal, getDailySummary, getWeeklyData, setDailyGoal } from './tracker'
import { renderDailySummary, renderWeeklyChart } from './render'
import { deleteMeal } from './store'

export type { FoodCategory, FoodItem, Meal, DailySummary, WeeklyData, DailyGoal } from './types'

export const addMeal = async (
  name: string,
  items: FoodItem[],
  timestamp?: string
) => {
  return logMeal(name, items, timestamp)
}

export const removeMeal = async (id: string) => {
  return deleteMeal(id)
}

export const updateGoal = async (calories: number) => {
  return setDailyGoal(calories)
}

export const viewDaily = async (date?: string) => {
  const summary = await getDailySummary(date)
  const template = renderDailySummary(summary)
  const ssr = createSSR()
  return { data: summary, html: ssr(template) }
}

export const viewWeekly = async () => {
  const data = await getWeeklyData()
  const template = renderWeeklyChart(data)
  const ssr = createSSR()
  return { data, html: ssr(template) }
}

export { getDailySummary, getWeeklyData, setDailyGoal } from './tracker'

{
  "name": "@node/expense-logger",
  "version": "1.0.0",
  "description": "Track expenses with category breakdowns, pie charts, filtering, and CSV export",
  "modnet": {
    "contentType": "finance",
    "structure": "collection",
    "mechanics": ["filter", "chart", "track"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type Category = 'food' | 'transport' | 'housing' | 'entertainment' | 'utilities' | 'other';

export const CATEGORIES: Category[] = ['food', 'transport', 'housing', 'entertainment', 'utilities', 'other'];

export type Expense = {
  id: string;
  amount: number;
  category: Category;
  date: string; // ISO date string YYYY-MM-DD
  notes: string;
  createdAt: string; // ISO timestamp
};

export type ExpenseFilter = {
  startDate?: string;
  endDate?: string;
  category?: Category;
};

export type CategorySummary = {
  category: Category;
  total: number;
  count: number;
  percentage: number;
};

export type MonthlySummary = {
  month: string; // YYYY-MM
  total: number;
  categories: CategorySummary[];
};

export const CATEGORY_COLORS: Record<Category, string> = {
  food: '#ef4444',
  transport: '#3b82f6',
  housing: '#22c55e',
  entertainment: '#a855f7',
  utilities: '#f59e0b',
  other: '#6b7280',
};

export const CATEGORY_LABELS: Record<Category, string> = {
  food: 'Food',
  transport: 'Transport',
  housing: 'Housing',
  entertainment: 'Entertainment',
  utilities: 'Utilities',
  other: 'Other',
};

import { type Expense, type ExpenseFilter, type Category } from './types';

const DATA_PATH = `${import.meta.dir}/data/expenses.jsonl`;

const generateId = (): string => crypto.randomUUID();

const readAllExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH);
  if (!(await file.exists())) return [];
  const text = await file.text();
  if (!text.trim()) return [];
  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as Expense);
};

const writeAllExpenses = async (expenses: Expense[]): Promise<void> => {
  const content = expenses.map((e) => JSON.stringify(e)).join('\n');
  await Bun.write(DATA_PATH, content + (expenses.length ? '\n' : ''));
};

const addExpense = async (input: {
  amount: number;
  category: Category;
  date: string;
  notes?: string;
}): Promise<Expense> => {
  const expense: Expense = {
    id: generateId(),
    amount: Math.round(input.amount * 100) / 100,
    category: input.category,
    date: input.date,
    notes: input.notes ?? '',
    createdAt: new Date().toISOString(),
  };
  const file = Bun.file(DATA_PATH);
  const existing = (await file.exists()) ? await file.text() : '';
  await Bun.write(DATA_PATH, existing + JSON.stringify(expense) + '\n');
  return expense;
};

const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await readAllExpenses();
  const filtered = expenses.filter((e) => e.id !== id);
  if (filtered.length === expenses.length) return false;
  await writeAllExpenses(filtered);
  return true;
};

const filterExpenses = (expenses: Expense[], filter: ExpenseFilter): Expense[] => {
  return expenses.filter((e) => {
    if (filter.startDate && e.date < filter.startDate) return false;
    if (filter.endDate && e.date > filter.endDate) return false;
    if (filter.category && e.category !== filter.category) return false;
    return true;
  });
};

const getExpensesByMonth = (expenses: Expense[], month: string): Expense[] => {
  return expenses.filter((e) => e.date.startsWith(month));
};

export { readAllExpenses, addExpense, deleteExpense, filterExpenses, getExpensesByMonth };

import { type Expense, type MonthlySummary, type CategorySummary, CATEGORIES } from './types';

const buildCategorySummaries = (expenses: Expense[], total: number): CategorySummary[] => {
  const grouped = new Map<string, { total: number; count: number }>();
  for (const cat of CATEGORIES) {
    grouped.set(cat, { total: 0, count: 0 });
  }
  for (const e of expenses) {
    const entry = grouped.get(e.category)!;
    entry.total += e.amount;
    entry.count += 1;
  }
  return CATEGORIES
    .map((category) => {
      const entry = grouped.get(category)!;
      return {
        category,
        total: Math.round(entry.total * 100) / 100,
        count: entry.count,
        percentage: total > 0 ? Math.round((entry.total / total) * 1000) / 10 : 0,
      };
    })
    .filter((s) => s.count > 0);
};

const buildMonthlySummary = (expenses: Expense[], month: string): MonthlySummary => {
  const monthExpenses = expenses.filter((e) => e.date.startsWith(month));
  const total = Math.round(monthExpenses.reduce((sum, e) => sum + e.amount, 0) * 100) / 100;
  return {
    month,
    total,
    categories: buildCategorySummaries(monthExpenses, total),
  };
};

const getAvailableMonths = (expenses: Expense[]): string[] => {
  const months = new Set(expenses.map((e) => e.date.slice(0, 7)));
  return [...months].sort().reverse();
};

export { buildMonthlySummary, buildCategorySummaries, getAvailableMonths };

import { type Expense } from './types';

const escapeCSVField = (value: string): string => {
  if (value.includes(',') || value.includes('"') || value.includes('\n')) {
    return `"${value.replace(/"/g, '""')}"`;
  }
  return value;
};

const exportToCSV = (expenses: Expense[]): string => {
  const header = 'Date,Category,Amount,Notes';
  const rows = expenses
    .sort((a, b) => a.date.localeCompare(b.date))
    .map((e) =>
      [
        e.date,
        e.category,
        e.amount.toFixed(2),
        escapeCSVField(e.notes),
      ].join(',')
    );
  return [header, ...rows].join('\n');
};

export { exportToCSV };

import { h } from 'plaited';
import { type CategorySummary, CATEGORY_COLORS, CATEGORY_LABELS } from './types';

const buildPieSlices = (categories: CategorySummary[]) => {
  const slices: ReturnType<typeof h>[] = [];
  let cumulativePercent = 0;

  for (const cat of categories) {
    const startAngle = cumulativePercent * 3.6; // 360 / 100
    const sliceAngle = cat.percentage * 3.6;
    const endAngle = startAngle + sliceAngle;

    const startRad = ((startAngle - 90) * Math.PI) / 180;
    const endRad = ((endAngle - 90) * Math.PI) / 180;

    const x1 = 50 + 40 * Math.cos(startRad);
    const y1 = 50 + 40 * Math.sin(startRad);
    const x2 = 50 + 40 * Math.cos(endRad);
    const y2 = 50 + 40 * Math.sin(endRad);

    const largeArc = sliceAngle > 180 ? 1 : 0;

    // Handle full circle (single category = 100%)
    if (cat.percentage >= 99.9) {
      slices.push(
        h('circle', {
          cx: '50',
          cy: '50',
          r: '40',
          fill: CATEGORY_COLORS[cat.category],
        })
      );
    } else {
      const d = [
        `M 50 50`,
        `L ${x1.toFixed(2)} ${y1.toFixed(2)}`,
        `A 40 40 0 ${largeArc} 1 ${x2.toFixed(2)} ${y2.toFixed(2)}`,
        'Z',
      ].join(' ');

      slices.push(
        h('path', {
          d,
          fill: CATEGORY_COLORS[cat.category],
          stroke: '#ffffff',
          'stroke-width': '0.5',
        })
      );
    }

    cumulativePercent += cat.percentage;
  }

  return slices;
};

const buildLegendItems = (categories: CategorySummary[]) => {
  return categories.map((cat) =>
    h(
      'div',
      {
        style: {
          display: 'flex',
          alignItems: 'center',
          gap: '8px',
          fontSize: '14px',
        },
      },
      h('span', {
        style: {
          width: '12px',
          height: '12px',
          borderRadius: '2px',
          backgroundColor: CATEGORY_COLORS[cat.category],
          display: 'inline-block',
          flexShrink: '0',
        },
      }),
      h('span', {}, `${CATEGORY_LABELS[cat.category]}: $${cat.total.toFixed(2)} (${cat.percentage}%)`)
    )
  );
};

const renderPieChart = (categories: CategorySummary[]) => {
  if (categories.length === 0) {
    return h('p', { style: { color: '#6b7280', fontStyle: 'italic' } }, 'No expenses to chart.');
  }

  return h(
    'div',
    {
      style: {
        display: 'flex',
        flexWrap: 'wrap',
        gap: '24px',
        alignItems: 'center',
        justifyContent: 'center',
      },
    },
    h(
      'svg',
      {
        viewBox: '0 0 100 100',
        width: '200',
        height: '200',
        style: { borderRadius: '50%', overflow: 'hidden' },
      },
      ...buildPieSlices(categories)
    ),
    h(
      'div',
      {
        style: {
          display: 'flex',
          flexDirection: 'column',
          gap: '6px',
        },
      },
      ...buildLegendItems(categories)
    )
  );
};

export { renderPieChart };

import { h } from 'plaited';
import {
