import { createSSR } from 'plaited';
import { type Category, type ExpenseFilter, CATEGORIES } from './types';
import { readAllExpenses, addExpense, deleteExpense, filterExpenses } from './store';
import { buildMonthlySummary, getAvailableMonths } from './summary';
import { exportToCSV } from './csv';
import { renderPage } from './view';

const isValidCategory = (value: string): value is Category =>
  CATEGORIES.includes(value as Category);

const isValidDate = (value: string): boolean =>
  /^\d{4}-\d{2}-\d{2}$/.test(value) && !isNaN(Date.parse(value));

const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const path = url.pathname;

  // API: Add expense
  if (path === '/api/expenses' && req.method === 'POST') {
    const body = await req.json();
    const { amount, category, date, notes } = body;

    if (typeof amount !== 'number' || amount <= 0) {
      return Response.json({ error: 'Amount must be a positive number' }, { status: 400 });
    }
    if (!isValidCategory(category)) {
      return Response.json({ error: `Invalid category. Must be one of: ${CATEGORIES.join(', ')}` }, { status: 400 });
    }
    if (!isValidDate(date)) {
      return Response.json({ error: 'Invalid date format. Use YYYY-MM-DD' }, { status: 400 });
    }

    const expense = await addExpense({ amount, category, date, notes: notes ?? '' });
    return Response.json(expense, { status: 201 });
  }

  // API: Delete expense
  if (path.startsWith('/api/expenses/') && req.method === 'DELETE') {
    const id = path.slice('/api/expenses/'.length);
    const deleted = await deleteExpense(id);
    if (!deleted) {
      return Response.json({ error: 'Expense not found' }, { status: 404 });
    }
    return Response.json({ success: true });
  }

  // API: List / filter expenses
  if (path === '/api/expenses' && req.method === 'GET') {
    const expenses = await readAllExpenses();
    const filter: ExpenseFilter = {};
    const startDate = url.searchParams.get('startDate');
    const endDate = url.searchParams.get('endDate');
    const category = url.searchParams.get('category');

    if (startDate) filter.startDate = startDate;
    if (endDate) filter.endDate = endDate;
    if (category && isValidCategory(category)) filter.category = category;

    const filtered = filterExpenses(expenses, filter);
    return Response.json(filtered);
  }

  // API: Monthly summary
  if (path === '/api/summary' && req.method === 'GET') {
    const expenses = await readAllExpenses();
    const month = url.searchParams.get('month') ?? new Date().toISOString().slice(0, 7);
    const summary = buildMonthlySummary(expenses, month);
    return Response.json(summary);
  }

  // API: Export CSV
  if (path === '/api/export' && req.method === 'GET') {
    const expenses = await readAllExpenses();
    const filter: ExpenseFilter = {};
    const startDate = url.searchParams.get('startDate');
    const endDate = url.searchParams.get('endDate');
    const category = url.searchParams.get('category');

    if (startDate) filter.startDate = startDate;
    if (endDate) filter.endDate = endDate;
    if (category && isValidCategory(category)) filter.category = category;

    const filtered = filterExpenses(expenses, filter);
    const csv = exportToCSV(filtered);
    return new Response(csv, {
      headers: {
        'Content-Type': 'text/csv',
        'Content-Disposition': 'attachment; filename="expenses.csv"',
      },
    });
  }

  // HTML: Main page
  if (path === '/' && req.method === 'GET') {
    const expenses = await readAllExpenses();
    const filter: ExpenseFilter = {};
    const startDate = url.searchParams.get('startDate');
    const endDate = url.searchParams.get('endDate');
    const category = url.searchParams.get('category');

    if (startDate) filter.startDate = startDate;
    if (endDate) filter.endDate = endDate;
    if (category && isValidCategory(category)) filter.category = category;

    const filteredExpenses = filterExpenses(expenses, filter);
    const months = getAvailableMonths(expenses);
    const selectedMonth = url.searchParams.get('month') ?? months[0] ?? new Date().toISOString().slice(0, 7);
    const summary = buildMonthlySummary(expenses, selectedMonth);

    const page = renderPage({
      expenses,
      filteredExpenses,
      summary,
      months,
      selectedMonth,
      filter,
    });

    const ssr = createSSR();
    const html = ssr(page);

    const fullHtml = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Expense Logger</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f9fafb; min-height: 100vh; }
  </style>
</head>
<body>
  ${html}
  <script>
    document.querySelector('[p-trigger="submit:addExpense"]')?.addEventListener('submit', async (e) => {
      e.preventDefault();
      const form = e.target;
      const data = {
        amount: parseFloat(form.amount.value),
        category: form.category.value,
        date: form.date.value,
        notes: form.notes.value,
      };
      await fetch('/api/expenses', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      });
      window.location.reload();
    });

    document.querySelector('[p-trigger="submit:filterExpenses"]')?.addEventListener('submit', (e) => {
      e.preventDefault();
      const form = e.target;
      const params = new URLSearchParams();
      if (form.startDate.value) params.set('startDate', form.startDate.value);
      if (form.endDate.value) params.set('endDate', form.endDate.value);
      if (form.category.value) params.set('category', form.category.value);
      window.location.search = params.toString();
    });

    document.querySelector('[p-trigger="click:clearFilter"]')?.addEventListener('click', () => {
      window.location.search = '';
    });

    document.querySelector('[p-trigger="change:selectMonth"]')?.addEventListener('change', (e) => {
      const params = new URLSearchParams(window.location.search);
      params.set('month', e.target.value);
      window.location.search = params.toString();
    });

    document.querySelector('[p-trigger="click:exportCSV"]')?.addEventListener('click', () => {
      const params = new URLSearchParams(window.location.search);
      window.location.href = '/api/export?' + params.toString();
    });

    document.querySelectorAll('[p-trigger="click:deleteExpense"]').forEach((btn) => {
      btn.addEventListener('click', async () => {
        if (!confirm('Delete this expense?')) return;
        const id = btn.getAttribute('data-id');
        await fetch('/api/expenses/' + id, { method: 'DELETE' });
        window.location.reload();
      });
    });
  </script>
</body>
</html>`;

    return new Response(fullHtml, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    });
  }

  return Response.json({ error: 'Not found' }, { status: 404 });
};

