import type { InventoryItem, NewItemInput, BulkImportInput } from './types'

const DATA_PATH = `${import.meta.dir}/data/inventory.json`

const generateId = (): string => crypto.randomUUID()

const now = (): string => new Date().toISOString()

export const loadInventory = async (): Promise<InventoryItem[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) {
    await Bun.write(DATA_PATH, '[]')
    return []
  }
  const text = await file.text()
  return JSON.parse(text) as InventoryItem[]
}

export const saveInventory = async (items: InventoryItem[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(items, null, 2))
}

export const addItem = async (input: NewItemInput): Promise<InventoryItem> => {
  const items = await loadInventory()
  const existing = items.find((i) => i.sku === input.sku)
  if (existing) {
    throw new Error(`Item with SKU "${input.sku}" already exists`)
  }
  const item: InventoryItem = {
    id: generateId(),
    name: input.name,
    sku: input.sku,
    quantity: input.quantity,
    category: input.category,
    reorderThreshold: input.reorderThreshold,
    createdAt: now(),
    updatedAt: now(),
  }
  items.push(item)
  await saveInventory(items)
  return item
}

export const updateItem = async (
  id: string,
  updates: Partial<Omit<InventoryItem, 'id' | 'createdAt' | 'updatedAt'>>,
): Promise<InventoryItem> => {
  const items = await loadInventory()
  const index = items.findIndex((i) => i.id === id)
  if (index === -1) {
    throw new Error(`Item with id "${id}" not found`)
  }
  if (updates.sku && updates.sku !== items[index].sku) {
    const skuConflict = items.find((i) => i.sku === updates.sku && i.id !== id)
    if (skuConflict) {
      throw new Error(`Item with SKU "${updates.sku}" already exists`)
    }
  }
  items[index] = {
    ...items[index],
    ...updates,
    updatedAt: now(),
  }
  await saveInventory(items)
  return items[index]
}

export const deleteItem = async (id: string): Promise<void> => {
  const items = await loadInventory()
  const filtered = items.filter((i) => i.id !== id)
  if (filtered.length === items.length) {
    throw new Error(`Item with id "${id}" not found`)
  }
  await saveInventory(filtered)
}

export const adjustQuantity = async (id: string, delta: number): Promise<InventoryItem> => {
  const items = await loadInventory()
  const index = items.findIndex((i) => i.id === id)
  if (index === -1) {
    throw new Error(`Item with id "${id}" not found`)
  }
  const newQty = items[index].quantity + delta
  if (newQty < 0) {
    throw new Error(`Cannot reduce quantity below 0 (current: ${items[index].quantity}, delta: ${delta})`)
  }
  items[index].quantity = newQty
  items[index].updatedAt = now()
  await saveInventory(items)
  return items[index]
}

export const bulkImport = async (inputs: BulkImportInput[]): Promise<{ added: number; skipped: string[] }> => {
  const items = await loadInventory()
  const existingSkus = new Set(items.map((i) => i.sku))
  const skipped: string[] = []
  const timestamp = now()

  for (const input of inputs) {
    if (existingSkus.has(input.sku)) {
      skipped.push(input.sku)
      continue
    }
    items.push({
      id: generateId(),
      name: input.name,
      sku: input.sku,
      quantity: input.quantity,
      category: input.category,
      reorderThreshold: input.reorderThreshold,
      createdAt: timestamp,
      updatedAt: timestamp,
    })
    existingSkus.add(input.sku)
  }

  await saveInventory(items)
  return { added: inputs.length - skipped.length, skipped }
}

export const findBySku = async (sku: string): Promise<InventoryItem | undefined> => {
  const items = await loadInventory()
  return items.find((i) => i.sku === sku)
}

import type { InventoryItem, SearchQuery } from './types'
import { loadInventory } from './store'

export const searchItems = async (query: SearchQuery): Promise<InventoryItem[]> => {
  const items = await loadInventory()
  const term = query.term.toLowerCase().trim()

  return items.filter((item) => {
    const matchesTerm =
      !term || item.name.toLowerCase().includes(term) || item.sku.toLowerCase().includes(term)

    const matchesCategory = !query.category || item.category === query.category

    return matchesTerm && matchesCategory
  })
}

export const getCategories = async (): Promise<string[]> => {
  const items = await loadInventory()
  const categories = new Set(items.map((i) => i.category))
  return [...categories].sort()
}

export const getLowStockItems = async (): Promise<InventoryItem[]> => {
  const items = await loadInventory()
  return items.filter((item) => item.quantity <= item.reorderThreshold)
}

export const sortItems = (
  items: InventoryItem[],
  by: 'name' | 'sku' | 'quantity' | 'category',
  direction: 'asc' | 'desc' = 'asc',
): InventoryItem[] => {
  const sorted = [...items].sort((a, b) => {
    const aVal = a[by]
    const bVal = b[by]
    if (typeof aVal === 'string' && typeof bVal === 'string') {
      return aVal.localeCompare(bVal)
    }
    if (typeof aVal === 'number' && typeof bVal === 'number') {
      return aVal - bVal
    }
    return 0
  })
  return direction === 'desc' ? sorted.reverse() : sorted
}

import type { DashboardStats, InventoryItem } from './types'
import { loadInventory } from './store'

export const getDashboardStats = async (): Promise<DashboardStats> => {
  const items = await loadInventory()
  const lowStockItems = items.filter((item) => item.quantity <= item.reorderThreshold)
  const categories = [...new Set(items.map((i) => i.category))].sort()
  const totalQuantity = items.reduce((sum, item) => sum + item.quantity, 0)

  return {
    totalItems: items.length,
    totalQuantity,
    lowStockItems,
    categories,
  }
}

export const getStockStatus = (item: InventoryItem): 'critical' | 'low' | 'ok' => {
  if (item.quantity === 0) return 'critical'
  if (item.quantity <= item.reorderThreshold) return 'low'
  return 'ok'
}

export const getCategorySummary = async (): Promise<
  { category: string; count: number; totalQuantity: number; lowStockCount: number }[]
> => {
  const items = await loadInventory()
  const categoryMap = new Map<string, { count: number; totalQuantity: number; lowStockCount: number }>()

  for (const item of items) {
    const existing = categoryMap.get(item.category) ?? { count: 0, totalQuantity: 0, lowStockCount: 0 }
    existing.count++
    existing.totalQuantity += item.quantity
    if (item.quantity <= item.reorderThreshold) {
      existing.lowStockCount++
    }
    categoryMap.set(item.category, existing)
  }

  return [...categoryMap.entries()]
    .map(([category, stats]) => ({ category, ...stats }))
    .sort((a, b) => a.category.localeCompare(b.category))
}

