export const renderDashboardHTML = async (searchTerm?: string, category?: string): Promise<string> => {
  const stats = await getDashboardStats()
  let items = await loadInventory()

  if (searchTerm || category) {
    items = await searchItems({ term: searchTerm ?? '', category })
  }

  const template = renderDashboard(stats, items)
  const ssr = createSSR()
  return ssr(template)
}

export const handleBarcodeLookup = async (sku: string): Promise<{
  found: boolean
  item?: Awaited<ReturnType<typeof findBySku>>
}> => {
  const item = await findBySku(sku.trim())
  return { found: !!item, item: item ?? undefined }
}

export const handleBulkImport = async (jsonString: string): Promise<{
  success: boolean
  added?: number
  skipped?: string[]
  error?: string
}> => {
  try {
    const parsed = JSON.parse(jsonString) as BulkImportInput[]
    if (!Array.isArray(parsed)) {
      return { success: false, error: 'Input must be a JSON array' }
    }

    for (const item of parsed) {
      if (!item.name || !item.sku || item.quantity == null || !item.category || item.reorderThreshold == null) {
        return {
          success: false,
          error: `Invalid item: each item must have name, sku, quantity, category, and reorderThreshold`,
        }
      }
    }

    const result = await bulkImport(parsed)
    return { success: true, added: result.added, skipped: result.skipped }
  } catch (err) {
    return { success: false, error: err instanceof Error ? err.message : 'Unknown error' }
  }
}

export const handleAddItem = async (input: NewItemInput): Promise<{
  success: boolean
  item?: Awaited<ReturnType<typeof addItem>>
  error?: string
}> => {
  try {
    if (!input.name?.trim()) return { success: false, error: 'Name is required' }
    if (!input.sku?.trim()) return { success: false, error: 'SKU is required' }
    if (input.quantity < 0) return { success: false, error: 'Quantity cannot be negative' }
    if (input.reorderThreshold < 0) return { success: false, error: 'Reorder threshold cannot be negative' }
    if (!input.category?.trim()) return { success: false, error: 'Category is required' }

    const item = await addItem({
      ...input,
      name: input.name.trim(),
      sku: input.sku.trim(),
      category: input.category.trim(),
    })
    return { success: true, item }
  } catch (err) {
    return { success: false, error: err instanceof Error ? err.message : 'Unknown error' }
  }
}

export const handleDeleteItem = async (id: string): Promise<{ success: boolean; error?: string }> => {
  try {
    await deleteItem(id)
    return { success: true }
  } catch (err) {
    return { success: false, error: err instanceof Error ? err.message : 'Unknown error' }
  }
}

export const handleAdjustQuantity = async (
  id: string,
  delta: number,
): Promise<{ success: boolean; error?: string }> => {
  try {
    await adjustQuantity(id, delta)
    return { success: true }
  } catch (err) {
    return { success: false, error: err instanceof Error ? err.message : 'Unknown error' }
  }
}

