import { h } from 'plaited'
import type { TemplateObject } from 'plaited'

/**
 * Parse markdown-style bold and italic in message text.
 * Supports **bold** and *italic* syntax.
 * Returns an array of template nodes (strings and elements).
 */
export const formatMessage = (text: string): (string | TemplateObject)[] => {
  const nodes: (string | TemplateObject)[] = []
  // Match **bold** or *italic* — bold checked first to avoid conflict
  const pattern = /\*\*(.+?)\*\*|\*(.+?)\*/g
  let lastIndex = 0
  let match: RegExpExecArray | null

  while ((match = pattern.exec(text)) !== null) {
    // Add preceding plain text
    if (match.index > lastIndex) {
      nodes.push(text.slice(lastIndex, match.index))
    }

    if (match[1] !== undefined) {
      // **bold**
      nodes.push(h('strong', {}, match[1]))
    } else if (match[2] !== undefined) {
      // *italic*
      nodes.push(h('em', {}, match[2]))
    }

    lastIndex = match.index + match[0].length
  }

  // Add remaining plain text
  if (lastIndex < text.length) {
    nodes.push(text.slice(lastIndex))
  }

  return nodes.length > 0 ? nodes : [text]
}

import type { Room, Message, ReadCursors } from './types'

const DATA_DIR = './data'

const roomsPath = `${DATA_DIR}/rooms.json`
const cursorsPath = `${DATA_DIR}/read-cursors.json`

const messagesPath = (roomId: string) =>
  `${DATA_DIR}/messages-${roomId}.jsonl`

// --- Rooms ---

export const loadRooms = async (): Promise<Room[]> => {
  const file = Bun.file(roomsPath)
  if (!(await file.exists())) return []
  return file.json()
}

export const saveRooms = async (rooms: Room[]): Promise<void> => {
  await Bun.write(roomsPath, JSON.stringify(rooms, null, 2))
}

export const createRoom = async (name: string, createdBy: string): Promise<Room> => {
  const rooms = await loadRooms()
  const room: Room = {
    id: crypto.randomUUID(),
    name,
    createdBy,
    createdAt: Date.now(),
    members: [createdBy],
  }
  rooms.push(room)
  await saveRooms(rooms)
  return room
}

export const joinRoom = async (roomId: string, userId: string): Promise<Room | null> => {
  const rooms = await loadRooms()
  const room = rooms.find((r) => r.id === roomId)
  if (!room) return null
  if (!room.members.includes(userId)) {
    room.members.push(userId)
    await saveRooms(rooms)
  }
  return room
}

// --- Messages ---

export const loadMessages = async (roomId: string): Promise<Message[]> => {
  const file = Bun.file(messagesPath(roomId))
  if (!(await file.exists())) return []
  const content = await file.text()
  return content
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Message)
}

export const appendMessage = async (
  roomId: string,
  sender: string,
  text: string,
): Promise<Message> => {
  const message: Message = {
    id: crypto.randomUUID(),
    roomId,
    sender,
    text,
    timestamp: Date.now(),
  }
  const file = Bun.file(messagesPath(roomId))
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(messagesPath(roomId), existing + JSON.stringify(message) + '\n')
  return message
}

// --- Read Cursors ---

export const loadCursors = async (): Promise<ReadCursors> => {
  const file = Bun.file(cursorsPath)
  if (!(await file.exists())) return {}
  return file.json()
}

export const saveCursors = async (cursors: ReadCursors): Promise<void> => {
  await Bun.write(cursorsPath, JSON.stringify(cursors, null, 2))
}

export const markRoomRead = async (
  userId: string,
  roomId: string,
  lastMessageId: string,
): Promise<void> => {
  const cursors = await loadCursors()
  if (!cursors[userId]) cursors[userId] = {}
  cursors[userId][roomId] = lastMessageId
  await saveCursors(cursors)
}

export const getUnreadCount = async (
  userId: string,
  roomId: string,
): Promise<number> => {
  const [cursors, messages] = await Promise.all([
    loadCursors(),
    loadMessages(roomId),
  ])
  const lastReadId = cursors[userId]?.[roomId]
  if (!lastReadId) return messages.length
  const lastReadIndex = messages.findIndex((m) => m.id === lastReadId)
  if (lastReadIndex === -1) return messages.length
  return messages.length - lastReadIndex - 1
}

