import {
  loadRooms,
  createRoom,
  joinRoom,
  loadMessages,
  appendMessage,
  markRoomRead,
  getUnreadCount,
} from './store'
import { renderApp, renderToHTML } from './render'
import type { RoomWithUnread, TypingState } from './types'

// In-memory typing state (ephemeral, not persisted)
const typingState: TypingState = {}

const TYPING_TIMEOUT_MS = 3000

export const setTyping = (roomId: string, user: string): void => {
  if (!typingState[roomId]) typingState[roomId] = []
  const existing = typingState[roomId].find((t) => t.user === user)
  const expiresAt = Date.now() + TYPING_TIMEOUT_MS
  if (existing) {
    existing.expiresAt = expiresAt
  } else {
    typingState[roomId].push({ user, expiresAt })
  }
}

export const getTypingUsers = (roomId: string, excludeUser?: string): string[] => {
  if (!typingState[roomId]) return []
  const now = Date.now()
  typingState[roomId] = typingState[roomId].filter((t) => t.expiresAt > now)
  return typingState[roomId]
    .filter((t) => t.user !== excludeUser)
    .map((t) => t.user)
}

export const handleCreateRoom = async (name: string, userId: string) => {
  const room = await createRoom(name, userId)
  return room
}

export const handleJoinRoom = async (roomId: string, userId: string) => {
  const room = await joinRoom(roomId, userId)
  if (!room) return null

  const messages = await loadMessages(roomId)
  if (messages.length > 0) {
    await markRoomRead(userId, roomId, messages[messages.length - 1].id)
  }
  return { room, messages }
}

export const handleSendMessage = async (
  roomId: string,
  sender: string,
  text: string,
) => {
  if (!text.trim()) return null
  const message = await appendMessage(roomId, sender, text.trim())
  // Clear typing state for this user in this room
  if (typingState[roomId]) {
    typingState[roomId] = typingState[roomId].filter((t) => t.user !== sender)
  }
  return message
}

export const getRoomsWithUnread = async (userId: string): Promise<RoomWithUnread[]> => {
  const rooms = await loadRooms()
  const roomsWithUnread: RoomWithUnread[] = await Promise.all(
    rooms.map(async (room) => ({
      ...room,
      unreadCount: await getUnreadCount(userId, room.id),
    })),
  )
  return roomsWithUnread
}

export const renderChatPage = async (
  userId: string,
  activeRoomId: string | null = null,
): Promise<string> => {
  const rooms = await getRoomsWithUnread(userId)
  let messages: Awaited<ReturnType<typeof loadMessages>> = []
  let activeRoomName = ''
  let typingUsers: string[] = []

  if (activeRoomId) {
    const activeRoom = rooms.find((r) => r.id === activeRoomId)
    if (activeRoom) {
      activeRoomName = activeRoom.name
      messages = await loadMessages(activeRoomId)
      typingUsers = getTypingUsers(activeRoomId, userId)

      // Mark as read
      if (messages.length > 0) {
        await markRoomRead(userId, activeRoomId, messages[messages.length - 1].id)
        // Update unread count after marking read
        const roomEntry = rooms.find((r) => r.id === activeRoomId)
        if (roomEntry) roomEntry.unreadCount = 0
      }
    }
  }

  const template = renderApp(rooms, activeRoomId, messages, activeRoomName, typingUsers)
  return renderToHTML(template)
}

export {
  createRoom,
  joinRoom,
  loadRooms,
  loadMessages,
  appendMessage,
  markRoomRead,
  getUnreadCount,
}

