export type WeatherCondition = {
  id: number
  main: string
  description: string
  icon: string
}

export type CurrentWeather = {
  coord: { lon: number; lat: number }
  weather: WeatherCondition[]
  main: {
    temp: number
    feels_like: number
    temp_min: number
    temp_max: number
    pressure: number
    humidity: number
  }
  visibility: number
  wind: { speed: number; deg: number; gust?: number }
  clouds: { all: number }
  dt: number
  sys: { country: string; sunrise: number; sunset: number }
  name: string
}

export type ForecastEntry = {
  dt: number
  main: {
    temp: number
    feels_like: number
    temp_min: number
    temp_max: number
    pressure: number
    humidity: number
  }
  weather: WeatherCondition[]
  wind: { speed: number; deg: number; gust?: number }
  dt_txt: string
}

export type ForecastResponse = {
  list: ForecastEntry[]
  city: {
    name: string
    country: string
    coord: { lat: number; lon: number }
  }
}

export type DayForecast = {
  date: string
  dayName: string
  tempMin: number
  tempMax: number
  humidity: number
  wind: number
  description: string
  icon: string
}

export type WeatherDashboardData = {
  current: CurrentWeather
  forecast: ForecastResponse
  dailyForecasts: DayForecast[]
}

import type { CurrentWeather, ForecastResponse, DayForecast, WeatherDashboardData } from './types'

const WEATHER_ICONS: Record<string, string> = {
  '01d': '\u2600\uFE0F', '01n': '\uD83C\uDF19',
  '02d': '\u26C5', '02n': '\uD83C\uDF19',
  '03d': '\u2601\uFE0F', '03n': '\u2601\uFE0F',
  '04d': '\uD83C\uDF25\uFE0F', '04n': '\uD83C\uDF25\uFE0F',
  '09d': '\uD83C\uDF27\uFE0F', '09n': '\uD83C\uDF27\uFE0F',
  '10d': '\uD83C\uDF26\uFE0F', '10n': '\uD83C\uDF27\uFE0F',
  '11d': '\u26C8\uFE0F', '11n': '\u26C8\uFE0F',
  '13d': '\u2744\uFE0F', '13n': '\u2744\uFE0F',
  '50d': '\uD83C\uDF2B\uFE0F', '50n': '\uD83C\uDF2B\uFE0F',
}

const DAY_NAMES = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday']

const toFahrenheit = (celsius: number): number => Math.round((celsius * 9) / 5 + 32)

const toCelsius = (kelvin: number): number => Math.round(kelvin - 273.15)

export const formatTemp = (kelvin: number): string => {
  const c = toCelsius(kelvin)
  const f = toFahrenheit(c)
  return `${c}°C / ${f}°F`
}

export const formatTempC = (kelvin: number): number => toCelsius(kelvin)

export const getWeatherIcon = (iconCode: string): string =>
  WEATHER_ICONS[iconCode] ?? '\u2601\uFE0F'

const generatePlaceholderCurrent = (city: string): CurrentWeather => {
  const now = Math.floor(Date.now() / 1000)
  return {
    coord: { lon: -0.1257, lat: 51.5085 },
    weather: [{ id: 802, main: 'Clouds', description: 'scattered clouds', icon: '03d' }],
    main: {
      temp: 288.55,
      feels_like: 286.82,
      temp_min: 286.15,
      temp_max: 290.93,
      pressure: 1012,
      humidity: 72,
    },
    visibility: 10000,
    wind: { speed: 4.12, deg: 250, gust: 7.2 },
    clouds: { all: 40 },
    dt: now,
    sys: { country: 'GB', sunrise: now - 21600, sunset: now + 21600 },
    name: city,
  }
}

const generatePlaceholderForecast = (city: string): ForecastResponse => {
  const now = Date.now()
  const baseTemp = 288
  const list = Array.from({ length: 40 }, (_, i) => {
    const dt = Math.floor((now + i * 3 * 3600 * 1000) / 1000)
    const dtDate = new Date(dt * 1000)
    const hourVariation = Math.sin((i * Math.PI) / 4) * 3
    const dayVariation = Math.sin((i * Math.PI) / 20) * 5
    const temp = baseTemp + hourVariation + dayVariation

    return {
      dt,
      main: {
        temp: Math.round(temp * 100) / 100,
        feels_like: temp - 1.5,
        temp_min: temp - 2,
        temp_max: temp + 2,
        pressure: 1012 + Math.round(Math.sin(i) * 5),
        humidity: 65 + Math.round(Math.sin(i * 0.5) * 15),
      },
      weather: [
        {
          id: i % 5 === 0 ? 500 : i % 3 === 0 ? 802 : 800,
          main: i % 5 === 0 ? 'Rain' : i % 3 === 0 ? 'Clouds' : 'Clear',
          description: i % 5 === 0 ? 'light rain' : i % 3 === 0 ? 'scattered clouds' : 'clear sky',
          icon: i % 5 === 0 ? '10d' : i % 3 === 0 ? '03d' : '01d',
        },
      ],
      wind: {
        speed: 3 + Math.round(Math.random() * 5 * 10) / 10,
        deg: Math.round(Math.random() * 360),
      },
      dt_txt: dtDate.toISOString().replace('T', ' ').slice(0, 19),
    }
  })

  return {
    list,
    city: {
      name: city,
      country: 'GB',
      coord: { lat: 51.5085, lon: -0.1257 },
    },
  }
}

const aggregateDailyForecasts = (forecast: ForecastResponse): DayForecast[] => {
  const dayMap = new Map<string, { temps: number[]; humidities: number[]; winds: number[]; entries: typeof forecast.list }>()

  for (const entry of forecast.list) {
    const date = new Date(entry.dt * 1000)
    const key = date.toISOString().slice(0, 10)
    const existing = dayMap.get(key) ?? { temps: [], humidities: [], winds: [], entries: [] }
    existing.temps.push(entry.main.temp)
    existing.humidities.push(entry.main.humidity)
    existing.winds.push(entry.wind.speed)
    existing.entries.push(entry)
    dayMap.set(key, existing)
  }

  const days: DayForecast[] = []
  for (const [dateStr, data] of dayMap) {
    if (days.length >= 5) break
    const date = new Date(dateStr)
    const midEntry = data.entries[Math.floor(data.entries.length / 2)]
    days.push({
      date: dateStr,
      dayName: DAY_NAMES[date.getDay()],
      tempMin: Math.min(...data.temps),
      tempMax: Math.max(...data.temps),
      humidity: Math.round(data.humidities.reduce((a, b) => a + b, 0) / data.humidities.length),
      wind: Math.round((data.winds.reduce((a, b) => a + b, 0) / data.winds.length) * 10) / 10,
      description: midEntry.weather[0].description,
      icon: midEntry.weather[0].icon,
    })
  }

  return days
}

export const fetchWeatherData = async (city: string, apiKey?: string): Promise<WeatherDashboardData> => {
  if (apiKey) {
    const baseUrl = 'https://api.openweathermap.org/data/2.5'
    const [currentRes, forecastRes] = await Promise.all([
      fetch(`${baseUrl}/weather?q=${encodeURIComponent(city)}&appid=${apiKey}`),
      fetch(`${baseUrl}/forecast?q=${encodeURIComponent(city)}&appid=${apiKey}`),
    ])

    if (!currentRes.ok) throw new Error(`Weather API error: ${currentRes.statusText}`)
    if (!forecastRes.ok) throw new Error(`Forecast API error: ${forecastRes.statusText}`)

    const current = (await currentRes.json()) as CurrentWeather
    const forecast = (await forecastRes.json()) as ForecastResponse
    const dailyForecasts = aggregateDailyForecasts(forecast)

    return { current, forecast, dailyForecasts }
  }

  const current = generatePlaceholderCurrent(city)
  const forecast = generatePlaceholderForecast(city)
  const dailyForecasts = aggregateDailyForecasts(forecast)

  return { current, forecast, dailyForecasts }
}

export const saveWeatherData = async (data: WeatherDashboardData): Promise<void> => {
  const path = './data/last-weather.json'
  await Bun.write(path, JSON.stringify(data, null, 2))
}

export const loadWeatherData = async (): Promise<WeatherDashboardData | null> => {
  const file = Bun.file('./data/last-weather.json')
  if (!(await file.exists())) return null
  return file.json() as Promise<WeatherDashboardData>
}

import { h } from 'plaited'
import type { ForecastResponse } from './types'
import { formatTempC } from './weather'

type ChartPoint = {
  x: number
  y: number
  temp: number
  label: string
}

const SVG_WIDTH = 720
const SVG_HEIGHT = 200
const PADDING = { top: 20, right: 20, bottom: 40, left: 50 }

const chartWidth = SVG_WIDTH - PADDING.left - PADDING.right
const chartHeight = SVG_HEIGHT - PADDING.top - PADDING.bottom

export const renderTemperatureChart = (forecast: ForecastResponse) => {
  const entries = forecast.list.slice(0, 24)

  const temps = entries.map((e) => formatTempC(e.main.temp))
  const minTemp = Math.min(...temps) - 2
  const maxTemp = Math.max(...temps) + 2
  const tempRange = maxTemp - minTemp || 1

  const points: ChartPoint[] = entries.map((entry, i) => {
    const temp = formatTempC(entry.main.temp)
    return {
      x: PADDING.left + (i / (entries.length - 1)) * chartWidth,
      y: PADDING.top + chartHeight - ((temp - minTemp) / tempRange) * chartHeight,
      temp,
      label: entry.dt_txt.slice(11, 16),
    }
  })

  const pathD = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ')

  const gradientD = `${pathD} L ${points[points.length - 1].x} ${PADDING.top + chartHeight} L ${points[0].x} ${PADDING.top + chartHeight} Z`

  const yTicks = 5
  const yLabels = Array.from({ length: yTicks + 1 }, (_, i) => {
    const temp = Math.round(minTemp + (i / yTicks) * tempRange)
    const y = PADDING.top + chartHeight - (i / yTicks) * chartHeight
    return { temp, y }
  })

  const xLabelInterval = Math.max(1, Math.floor(entries.length / 6))
  const xLabels = points.filter((_, i) => i % xLabelInterval === 0)

  const styles = {
    container: {
      width: '100%',
      maxWidth: `${SVG_WIDTH}px`,
      margin: '16px auto',
    },
    title: {
      fontSize: '14px',
      fontWeight: '600',
      color: '#374151',
      marginBottom: '8px',
    },
    svg: {
      width: '100%',
      height: 'auto',
      backgroundColor: '#f9fafb',
      borderRadius: '8px',
      border: '1px solid #e5e7eb',
    },
  }

  return h('div', { style: styles.container },
    h('div', { style: styles.title }, 'Temperature Trend (72h)'),
    h('svg', {
      viewBox: `0 0 ${SVG_WIDTH} ${SVG_HEIGHT}`,
      style: styles.svg,
      xmlns: 'http://www.w3.org/2000/svg',
    },
      h('defs', {},
        h('linearGradient', { id: 'tempGradient', x1: '0', y1: '0', x2: '0', y2: '1' },
          h('stop', { offset: '0%', 'stop-color': '#3b82f6', 'stop-opacity': '0.3' }),
          h('stop', { offset: '100%', 'stop-color': '#3b82f6', 'stop-opacity': '0.02' }),
        ),
      ),
      ...yLabels.map(({ temp, y }) =>
        h('g', {},
          h('line', {
            x1: String(PADDING.left),
            y1: String(y),
            x2: String(SVG_WIDTH - PADDING.right),
            y2: String(y),
            stroke: '#e5e7eb',
            'stroke-width': '1',
          }),
          h('text', {
            x: String(PADDING.left - 8),
            y: String(y + 4),
            'text-anchor': 'end',
            fill: '#6b7280',
            'font-size': '11',
          }, `${temp}°`),
        ),
      ),
      h('path', {
        d: gradientD,
        fill: 'url(#tempGradient)',
      }),
      h('path', {
        d: pathD,
        fill: 'none',
        stroke: '#3b82f6',
        'stroke-width': '2.5',
        'stroke-linecap': 'round',
        'stroke-linejoin': 'round',
      }),
      ...points.map((p) =>
        h('circle', {
          cx: String(p.x),
          cy: String(p.y),
          r: '3',
          fill: '#3b82f6',
          stroke: '#ffffff',
          'stroke-width': '1.5',
        }),
      ),
      ...xLabels.map((p) =>
        h('text', {
          x: String(p.x),
          y: String(PADDING.top + chartHeight + 20),
          'text-anchor': 'middle',
          fill: '#6b7280',
          'font-size': '10',
        }, p.label),
      ),
    ),
  )
}

