import { fetchWeatherData, saveWeatherData, loadWeatherData } from './weather'
import { renderDashboard } from './render'
import type { WeatherDashboardData } from './types'

export type { WeatherDashboardData } from './types'
export { fetchWeatherData, saveWeatherData, loadWeatherData } from './weather'
export { renderDashboard } from './render'

const DEFAULT_CITY = 'London'

const getCity = (): string => {
  const args = process.argv.slice(2)
  const cityFlag = args.indexOf('--city')
  if (cityFlag !== -1 && args[cityFlag + 1]) return args[cityFlag + 1]
  return args[0] ?? DEFAULT_CITY
}

const getApiKey = (): string | undefined => {
  const args = process.argv.slice(2)
  const keyFlag = args.indexOf('--api-key')
  if (keyFlag !== -1 && args[keyFlag + 1]) return args[keyFlag + 1]
  return process.env.OPENWEATHERMAP_API_KEY ?? undefined
}

const main = async () => {
  const city = getCity()
  const apiKey = getApiKey()

  console.log(`Fetching weather for: ${city}${apiKey ? '' : ' (using placeholder data)'}`)

  const data = await fetchWeatherData(city, apiKey)
  await saveWeatherData(data)

  const html = renderDashboard(data)
  const outputPath = './data/dashboard.html'
  await Bun.write(outputPath, html)

  console.log(`Dashboard saved to ${outputPath}`)
  console.log(`\nCurrent conditions in ${data.current.name}:`)
  console.log(`  Temperature: ${Math.round(data.current.main.temp - 273.15)}°C / ${Math.round((data.current.main.temp - 273.15) * 9 / 5 + 32)}°F`)
  console.log(`  Humidity: ${data.current.main.humidity}%`)
  console.log(`  Wind: ${data.current.wind.speed} m/s`)
  console.log(`  Conditions: ${data.current.weather[0].description}`)
  console.log(`\n5-Day Forecast:`)

  for (const day of data.dailyForecasts) {
    const minC = Math.round(day.tempMin - 273.15)
    const maxC = Math.round(day.tempMax - 273.15)
    console.log(`  ${day.dayName.slice(0, 3)}: ${minC}°C - ${maxC}°C, ${day.description}`)
  }
}

main().catch(console.error)

