export const getInsertText = (action: string): { before: string; after: string; placeholder: string } => {
  switch (action) {
    case 'h1':
      return { before: '# ', after: '', placeholder: 'Heading 1' }
    case 'h2':
      return { before: '## ', after: '', placeholder: 'Heading 2' }
    case 'h3':
      return { before: '### ', after: '', placeholder: 'Heading 3' }
    case 'bold':
      return { before: '**', after: '**', placeholder: 'bold text' }
    case 'italic':
      return { before: '*', after: '*', placeholder: 'italic text' }
    case 'link':
      return { before: '[', after: '](url)', placeholder: 'link text' }
    case 'image':
      return { before: '![', after: '](url)', placeholder: 'alt text' }
    case 'code':
      return { before: '`', after: '`', placeholder: 'code' }
    case 'codeblock':
      return { before: '```\n', after: '\n```', placeholder: 'code block' }
    case 'ul':
      return { before: '- ', after: '', placeholder: 'list item' }
    case 'ol':
      return { before: '1. ', after: '', placeholder: 'list item' }
    case 'blockquote':
      return { before: '> ', after: '', placeholder: 'quote' }
    case 'hr':
      return { before: '\n---\n', after: '', placeholder: '' }
    case 'table':
      return {
        before: '| Header 1 | Header 2 | Header 3 |\n| --- | --- | --- |\n| ',
        after: ' | Cell 2 | Cell 3 |',
        placeholder: 'Cell 1',
      }
    default:
      return { before: '', after: '', placeholder: '' }
  }
}

