export const renderPage = (content: string, title: string, docId: string | null) => {
  const previewHtml = parseMarkdown(content)

  return h(
    Fragment,
    {},
    h('style', {}, previewCss),
    h(
      'div',
      { style: styleToString(layoutStyles.container) },
      renderHeader(title, docId),
      renderToolbar(),
      renderEditor(content)
    ),
    h('script', {}, `
      const editor = document.querySelector('[p-target="editor"]');
      const preview = document.querySelector('[p-target="preview"]');
      const titleInput = document.querySelector('[p-target="title-input"]');

      // Initial preview render
      preview.innerHTML = ${JSON.stringify(previewHtml)};

      // Live preview update
      editor.addEventListener('input', async () => {
        const resp = await fetch('/api/preview', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ content: editor.value }),
        });
        const data = await resp.json();
        preview.innerHTML = data.html;
      });

      // Toolbar actions
      document.querySelectorAll('[p-trigger^="toolbar:"]').forEach(btn => {
        btn.addEventListener('click', async () => {
          const action = btn.getAttribute('p-trigger').split(':')[1];
          const resp = await fetch('/api/toolbar-action', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action }),
          });
          const data = await resp.json();
          const start = editor.selectionStart;
          const end = editor.selectionEnd;
          const selected = editor.value.substring(start, end);
          const insert = data.before + (selected || data.placeholder) + data.after;
          editor.value = editor.value.substring(0, start) + insert + editor.value.substring(end);
          editor.focus();
          const cursorPos = start + data.before.length + (selected || data.placeholder).length;
          editor.setSelectionRange(
            selected ? start + data.before.length : start + data.before.length,
            selected ? start + data.before.length + selected.length : start + data.before.length + data.placeholder.length
          );
          // Trigger preview update
          editor.dispatchEvent(new Event('input'));
        });
      });

      // Save
      document.querySelector('[p-trigger="save"]')?.addEventListener('click', async () => {
        const title = titleInput.value || 'Untitled';
        const body = { title, content: editor.value };
        const docId = document.body.dataset.docId;
        if (docId) body.id = docId;
        const resp = await fetch('/api/save', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(body),
        });
        const data = await resp.json();
        document.body.dataset.docId = data.id;
        alert('Document saved!');
      });

      // Load
      document.querySelector('[p-trigger="load"]')?.addEventListener('click', async () => {
        const resp = await fetch('/api/documents');
        const docs = await resp.json();
        const modal = document.createElement('div');
        modal.id = 'doc-modal';
        if (docs.length === 0) {
          modal.innerHTML = '<div style="${styleToString(modalStyles.overlay)}"><div style="${styleToString(modalStyles.modal)}"><div style="${styleToString(modalStyles.modalTitle)}">Saved Documents</div><div style="${styleToString(modalStyles.emptyState)}">No saved documents yet.</div><button style="${styleToString(modalStyles.closeBtn)}" onclick="this.closest(\\'#doc-modal\\').remove()">Close</button></div></div>';
        } else {
          let items = docs.map(d =>
            '<div style="${styleToString(modalStyles.docItem)}" data-id="' + d.id + '" class="doc-item"><div><div style="${styleToString(modalStyles.docTitle)}">' + (d.title || 'Untitled') + '</div><div style="${styleToString(modalStyles.docDate)}">Updated: ' + new Date(d.updatedAt).toLocaleDateString() + '</div></div></div>'
          ).join('');
          modal.innerHTML = '<div style="${styleToString(modalStyles.overlay)}"><div style="${styleToString(modalStyles.modal)}"><div style="${styleToString(modalStyles.modalTitle)}">Saved Documents</div>' + items + '<button style="${styleToString(modalStyles.closeBtn)}" onclick="this.closest(\\'#doc-modal\\').remove()">Close</button></div></div>';
        }
        document.body.appendChild(modal);
        modal.querySelector('[style*="position:fixed"]')?.addEventListener('click', (e) => {
          if (e.target === e.currentTarget) modal.remove();
        });
        modal.querySelectorAll('.doc-item').forEach(item => {
          item.addEventListener('click', async () => {
            const id = item.dataset.id;
            const docResp = await fetch('/api/documents/' + id);
            const doc = await docResp.json();
            editor.value = doc.content;
            titleInput.value = doc.title;
            document.body.dataset.docId = doc.id;
            editor.dispatchEvent(new Event('input'));
            modal.remove();
          });
        });
      });

      // New
      document.querySelector('[p-trigger="new"]')?.addEventListener('click', () => {
        editor.value = '';
        titleInput.value = '';
        delete document.body.dataset.docId;
        editor.dispatchEvent(new Event('input'));
      });

      // Delete
      document.querySelector('[p-trigger="delete"]')?.addEventListener('click', async () => {
        const docId = document.body.dataset.docId;
        if (!docId) return;
        if (!confirm('Delete this document?')) return;
        await fetch('/api/documents/' + docId, { method: 'DELETE' });
        editor.value = '';
        titleInput.value = '';
        delete document.body.dataset.docId;
        editor.dispatchEvent(new Event('input'));
      });

      // Set initial doc ID if editing existing
      ${docId ? `document.body.dataset.docId = ${JSON.stringify(docId)};` : ''}
    `)
  )
}

import { createSSR } from 'plaited'
import { parseMarkdown } from './markdown'
import { getInsertText } from './toolbar'
import { listDocuments, getDocument, saveDocument, deleteDocument } from './storage'
import { renderPage } from './render'

const ssr = createSSR()

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (element: ReturnType<typeof renderPage>) => {
  const html = ssr(element)
  return new Response(
    `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Markdown Editor</title></head><body>${html}</body></html>`,
    {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    }
  )
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname

    // API: Render markdown preview
    if (path === '/api/preview' && req.method === 'POST') {
      const body = (await req.json()) as { content: string }
      const html = parseMarkdown(body.content)
      return jsonResponse({ html })
    }

    // API: Get toolbar insert text
    if (path === '/api/toolbar-action' && req.method === 'POST') {
      const body = (await req.json()) as { action: string }
      const insertData = getInsertText(body.action)
      return jsonResponse(insertData)
    }

    // API: Save document
    if (path === '/api/save' && req.method === 'POST') {
      const body = (await req.json()) as { title: string; content: string; id?: string }
      const doc = await saveDocument(body.title, body.content, body.id)
      return jsonResponse(doc)
    }

    // API: List documents
    if (path === '/api/documents' && req.method === 'GET') {
      const docs = await listDocuments()
      return jsonResponse(docs)
    }

    // API: Get single document
    const docMatch = path.match(/^\/api\/documents\/(.+)$/)
    if (docMatch && req.method === 'GET') {
      const doc = await getDocument(docMatch[1])
      if (!doc) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse(doc)
    }

    // API: Delete document
    if (docMatch && req.method === 'DELETE') {
      const deleted = await deleteDocument(docMatch[1])
      return jsonResponse({ deleted })
    }

    // Main page
    if (path === '/' || path === '/editor') {
      const docId = url.searchParams.get('doc')
      let content = ''
      let title = ''
      let activeDocId: string | null = null

      if (docId) {
        const doc = await getDocument(docId)
        if (doc) {
          content = doc.content
          title = doc.title
          activeDocId = doc.id
        }
      }

      return htmlResponse(renderPage(content, title, activeDocId))
    }

    return new Response('Not Found', { status: 404 })
  },
})

