export type RGB = { r: number; g: number; b: number }
export type HSL = { h: number; s: number; l: number }

export const hexToRgb = (hex: string): RGB => {
  const cleaned = hex.replace(/^#/, '')
  const full =
    cleaned.length === 3
      ? cleaned
          .split('')
          .map((c) => c + c)
          .join('')
      : cleaned
  const num = parseInt(full, 16)
  return {
    r: (num >> 16) & 255,
    g: (num >> 8) & 255,
    b: num & 255,
  }
}

export const rgbToHex = ({ r, g, b }: RGB): string => {
  const toHex = (n: number) =>
    Math.round(Math.max(0, Math.min(255, n)))
      .toString(16)
      .padStart(2, '0')
  return `#${toHex(r)}${toHex(g)}${toHex(b)}`
}

export const rgbToHsl = ({ r, g, b }: RGB): HSL => {
  const rn = r / 255
  const gn = g / 255
  const bn = b / 255
  const max = Math.max(rn, gn, bn)
  const min = Math.min(rn, gn, bn)
  const l = (max + min) / 2
  if (max === min) return { h: 0, s: 0, l }
  const d = max - min
  const s = l > 0.5 ? d / (2 - max - min) : d / (max + min)
  let h = 0
  if (max === rn) h = ((gn - bn) / d + (gn < bn ? 6 : 0)) / 6
  else if (max === gn) h = ((bn - rn) / d + 2) / 6
  else h = ((rn - gn) / d + 4) / 6
  return { h: h * 360, s, l }
}

export const hslToRgb = ({ h, s, l }: HSL): RGB => {
  const hNorm = ((h % 360) + 360) % 360 / 360
  if (s === 0) {
    const v = Math.round(l * 255)
    return { r: v, g: v, b: v }
  }
  const hue2rgb = (p: number, q: number, t: number): number => {
    const tn = t < 0 ? t + 1 : t > 1 ? t - 1 : t
    if (tn < 1 / 6) return p + (q - p) * 6 * tn
    if (tn < 1 / 2) return q
    if (tn < 2 / 3) return p + (q - p) * (2 / 3 - tn) * 6
    return p
  }
  const q = l < 0.5 ? l * (1 + s) : l + s - l * s
  const p = 2 * l - q
  return {
    r: Math.round(hue2rgb(p, q, hNorm + 1 / 3) * 255),
    g: Math.round(hue2rgb(p, q, hNorm) * 255),
    b: Math.round(hue2rgb(p, q, hNorm - 1 / 3) * 255),
  }
}

export const hexToHsl = (hex: string): HSL => rgbToHsl(hexToRgb(hex))
export const hslToHex = (hsl: HSL): string => rgbToHex(hslToRgb(hsl))

export const formatRgb = ({ r, g, b }: RGB): string => `rgb(${r}, ${g}, ${b})`
export const formatHsl = ({ h, s, l }: HSL): string =>
  `hsl(${Math.round(h)}, ${Math.round(s * 100)}%, ${Math.round(l * 100)}%)`

export const isValidHex = (hex: string): boolean =>
  /^#?([0-9a-fA-F]{3}|[0-9a-fA-F]{6})$/.test(hex)

import { hexToRgb } from './color'
import type { RGB } from './color'

export type WcagLevel = 'AAA' | 'AA' | 'Fail'

export type ContrastResult = {
  ratio: number
  normalText: { aa: boolean; aaa: boolean; level: WcagLevel }
  largeText: { aa: boolean; aaa: boolean; level: WcagLevel }
}

const linearize = (channel: number): number => {
  const c = channel / 255
  return c <= 0.04045 ? c / 12.92 : Math.pow((c + 0.055) / 1.055, 2.4)
}

const relativeLuminance = ({ r, g, b }: RGB): number =>
  0.2126 * linearize(r) + 0.7152 * linearize(g) + 0.0722 * linearize(b)

export const contrastRatio = (hex1: string, hex2: string): number => {
  const l1 = relativeLuminance(hexToRgb(hex1))
  const l2 = relativeLuminance(hexToRgb(hex2))
  const lighter = Math.max(l1, l2)
  const darker = Math.min(l1, l2)
  return (lighter + 0.05) / (darker + 0.05)
}

const getLevel = (aa: boolean, aaa: boolean): WcagLevel => {
  if (aaa) return 'AAA'
  if (aa) return 'AA'
  return 'Fail'
}

export const checkContrast = (hex1: string, hex2: string): ContrastResult => {
  const ratio = contrastRatio(hex1, hex2)
  const normalAA = ratio >= 4.5
  const normalAAA = ratio >= 7
  const largeAA = ratio >= 3
  const largeAAA = ratio >= 4.5
  return {
    ratio: Math.round(ratio * 100) / 100,
    normalText: { aa: normalAA, aaa: normalAAA, level: getLevel(normalAA, normalAAA) },
    largeText: { aa: largeAA, aaa: largeAAA, level: getLevel(largeAA, largeAAA) },
  }
}

