const renderSwatchCard = (color: PaletteColor, selected: boolean): string => {
  const rgb = hexToRgb(color.hex)
  const hsl = hexToHsl(color.hex)
  const rgbStr = formatRgb(rgb)
  const hslStr = formatHsl(hsl)

  return h(
    'div',
    {
      style: styles.swatchCard(color.hex, selected),
      'p-trigger': 'click:selectColor',
      'data-hex': color.hex,
    },
    h('div', { style: styles.swatchColor(color.hex) }),
    h(
      'div',
      { style: styles.swatchInfo },
      h('div', { style: styles.swatchLabel }, color.label),
      h(
        'div',
        {
          style: styles.swatchValue,
          'p-trigger': 'click:copyValue',
          'data-value': color.hex,
        },
        color.hex,
        h('span', { style: styles.copyIcon }, 'copy'),
      ),
      h(
        'div',
        {
          style: styles.swatchValue,
          'p-trigger': 'click:copyValue',
          'data-value': rgbStr,
        },
        rgbStr,
        h('span', { style: styles.copyIcon }, 'copy'),
      ),
      h(
        'div',
        {
          style: styles.swatchValue,
          'p-trigger': 'click:copyValue',
          'data-value': hslStr,
        },
        hslStr,
        h('span', { style: styles.copyIcon }, 'copy'),
      ),
    ),
  )
}

const renderContrastChecker = (hex1: string, hex2: string): string => {
  const result = checkContrast(hex1, hex2)

  return h(
    'div',
    { style: styles.contrastSection },
    h('h2', { style: styles.contrastHeader }, 'Contrast Checker'),
    h(
      'div',
      { style: styles.contrastPreview(hex1, hex2) },
      `Sample text — ${hex1} on ${hex2}`,
    ),
    h(
      'div',
      { style: styles.contrastPreview(hex2, hex1) },
      `Sample text — ${hex2} on ${hex1}`,
    ),
    h(
      'div',
      { style: styles.ratioDisplay },
      `${result.ratio}:1`,
    ),
    h('div', { style: styles.ratioLabel }, 'Contrast Ratio'),
    h(
      'div',
      { style: styles.contrastGrid },
      h(
        'div',
        { style: styles.contrastCard },
        h('strong', {}, 'Normal Text'),
        h('div', {},
          'AA ',
          h('span', { style: styles.badge(result.normalText.aa) }, result.normalText.aa ? 'Pass' : 'Fail'),
        ),
        h('div', {},
          'AAA ',
          h('span', { style: styles.badge(result.normalText.aaa) }, result.normalText.aaa ? 'Pass' : 'Fail'),
        ),
      ),
      h(
        'div',
        { style: styles.contrastCard },
        h('strong', {}, 'Large Text'),
        h('div', {},
          'AA ',
          h('span', { style: styles.badge(result.largeText.aa) }, result.largeText.aa ? 'Pass' : 'Fail'),
        ),
        h('div', {},
          'AAA ',
          h('span', { style: styles.badge(result.largeText.aaa) }, result.largeText.aaa ? 'Pass' : 'Fail'),
        ),
      ),
    ),
  )
}

const renderSelectPrompt = (selectedCount: number): string => {
  if (selectedCount === 0) {
    return h('div', { style: styles.selectPrompt }, 'Click two swatches to compare contrast')
  }
  if (selectedCount === 1) {
    return h('div', { style: styles.selectPrompt }, 'Click one more swatch to compare contrast')
  }
  return ''
}

export type RenderOptions = {
  baseHex: string
  mode: HarmonyMode
  selectedColors: string[]
}

export const renderPalette = (options: RenderOptions): string => {
  const { baseHex, mode, selectedColors } = options
  const palette = generatePalette(baseHex, mode)

  const modeButtons = HARMONY_MODES.map((m) =>
    h(
      'button',
      {
        style: styles.modeButton(m.value === mode),
        'p-trigger': 'click:changeMode',
        'data-mode': m.value,
        title: m.description,
      },
      m.label,
    ),
  ).join('')

  const swatches = palette
    .map((color) => renderSwatchCard(color, selectedColors.includes(color.hex)))
    .join('')

  const contrastArea =
    selectedColors.length === 2
      ? renderContrastChecker(selectedColors[0], selectedColors[1])
      : renderSelectPrompt(selectedColors.length)

  return h(
    'div',
    { style: styles.container },
    h('h1', { style: styles.header }, 'Color Palette Generator'),
    h(
      'div',
      { style: styles.inputSection },
      h('input', {
        type: 'color',
        value: baseHex,
        style: styles.colorPicker,
        'p-trigger': 'input:changeBaseColor',
        'p-target': 'colorPicker',
      }),
      h('input', {
        type: 'text',
        value: baseHex,
        placeholder: '#4361ee',
        style: styles.hexInput,
        'p-trigger': 'change:changeBaseHex',
        'p-target': 'hexInput',
        maxlength: '7',
      }),
    ),
    h('div', { style: styles.modeSelector }, modeButtons),
    h('div', { style: styles.paletteGrid }, swatches),
    contrastArea,
  )
}

export const renderPage = (options: RenderOptions): string => {
  const ssr = createSSR()
  const body = renderPalette(options)
  return ssr(
    h(
      'html',
      { lang: 'en' },
      h(
        'head',
        {},
        h('meta', { charset: 'UTF-8' }),
        h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
        h('title', {}, 'Color Palette Generator'),
        h('style', {}, 'body { margin: 0; } * { box-sizing: border-box; }'),
      ),
      h('body', {}, body),
    ),
  )
}

import { renderPage, renderPalette } from './render'
import { generatePalette, HARMONY_MODES } from './harmony'
import { checkContrast, contrastRatio } from './contrast'
import { hexToRgb, hexToHsl, formatRgb, formatHsl, isValidHex, rgbToHex, hslToHex } from './color'
import type { RenderOptions } from './render'
import type { HarmonyMode, PaletteColor } from './harmony'
import type { ContrastResult } from './contrast'
import type { RGB, HSL } from './color'

const DATA_PATH = './data/palettes.json'

type SavedPalette = {
  id: string
  baseHex: string
  mode: HarmonyMode
  colors: PaletteColor[]
  createdAt: string
}

const loadPalettes = async (): Promise<SavedPalette[]> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json()
  }
  return []
}

const savePalette = async (palette: SavedPalette): Promise<void> => {
  const palettes = await loadPalettes()
  palettes.push(palette)
  await Bun.write(DATA_PATH, JSON.stringify(palettes, null, 2))
}

const createPalette = (baseHex: string, mode: HarmonyMode): SavedPalette => ({
  id: crypto.randomUUID(),
  baseHex,
  mode,
  colors: generatePalette(baseHex, mode),
  createdAt: new Date().toISOString(),
})

const defaultState: RenderOptions = {
  baseHex: '#4361ee',
  mode: 'complementary',
  selectedColors: [],
}

const serve = () => {
  let state = { ...defaultState }

  return Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/') {
        return new Response(renderPage(state), {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      if (url.pathname === '/api/palette' && req.method === 'GET') {
        const baseHex = url.searchParams.get('base') ?? state.baseHex
        const mode = (url.searchParams.get('mode') ?? state.mode) as HarmonyMode
        if (!isValidHex(baseHex)) {
          return Response.json({ error: 'Invalid hex color' }, { status: 400 })
        }
        const palette = generatePalette(baseHex, mode)
        return Response.json({ palette, baseHex, mode })
      }

      if (url.pathname === '/api/contrast' && req.method === 'GET') {
        const color1 = url.searchParams.get('color1')
        const color2 = url.searchParams.get('color2')
        if (!color1 || !color2 || !isValidHex(color1) || !isValidHex(color2)) {
          return Response.json({ error: 'Two valid hex colors required' }, { status: 400 })
        }
        const result = checkContrast(color1, color2)
        return Response.json(result)
      }

      if (url.pathname === '/api/save' && req.method === 'POST') {
        const body = await req.json() as { baseHex: string; mode: HarmonyMode }
        if (!isValidHex(body.baseHex)) {
          return Response.json({ error: 'Invalid hex color' }, { status: 400 })
        }
        const palette = createPalette(body.baseHex, body.mode)
        await savePalette(palette)
        return Response.json(palette)
      }

      if (url.pathname === '/api/palettes' && req.method === 'GET') {
        const palettes = await loadPalettes()
        return Response.json(palettes)
      }

      if (url.pathname === '/api/convert' && req.method === 'GET') {
        const hex = url.searchParams.get('hex')
        if (!hex || !isValidHex(hex)) {
          return Response.json({ error: 'Valid hex color required' }, { status: 400 })
        }
        const rgb = hexToRgb(hex)
        const hsl = hexToHsl(hex)
        return Response.json({
          hex: hex.startsWith('#') ? hex : `#${hex}`,
          rgb,
          hsl,
          rgbString: formatRgb(rgb),
          hslString: formatHsl(hsl),
        })
      }

      return new Response('Not found', { status: 404 })
    },
  })
}

export {
  generatePalette,
  checkContrast,
  contrastRatio,
  hexToRgb,
  hexToHsl,
  rgbToHex,
  hslToHex,
  formatRgb,
  formatHsl,
  isValidHex,
  renderPalette,
  renderPage,
  HARMONY_MODES,
  serve,
}

export type {
  HarmonyMode,
  PaletteColor,
  ContrastResult,
  RGB,
  HSL,
  RenderOptions,
  SavedPalette,
}

