import type { Project, GalleryFilters, SortField, SortOrder } from './types'

const DATA_PATH = './data/projects.json'

export const loadProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  const text = await file.text()
  return JSON.parse(text) as Project[]
}

export const saveProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2))
}

export const getProject = async (id: string): Promise<Project | undefined> => {
  const projects = await loadProjects()
  return projects.find((p) => p.id === id)
}

export const addProject = async (project: Project): Promise<void> => {
  const projects = await loadProjects()
  projects.push(project)
  await saveProjects(projects)
}

export const getAllTags = async (): Promise<string[]> => {
  const projects = await loadProjects()
  const tagSet = new Set<string>()
  for (const project of projects) {
    for (const tag of project.tags) {
      tagSet.add(tag)
    }
  }
  return [...tagSet].sort()
}

const sortProjects = (projects: Project[], field: SortField, order: SortOrder): Project[] => {
  const sorted = [...projects].sort((a, b) => {
    if (field === 'title') {
      return a.title.localeCompare(b.title)
    }
    return new Date(a.dateAdded).getTime() - new Date(b.dateAdded).getTime()
  })
  return order === 'desc' ? sorted.reverse() : sorted
}

export const filterProjects = async (filters: GalleryFilters): Promise<Project[]> => {
  let projects = await loadProjects()

  if (filters.search) {
    const query = filters.search.toLowerCase()
    projects = projects.filter((p) => p.title.toLowerCase().includes(query))
  }

  if (filters.tag) {
    const tag = filters.tag
    projects = projects.filter((p) => p.tags.includes(tag))
  }

  return sortProjects(projects, filters.sortField, filters.sortOrder)
}

