const renderClientScript = (filters: GalleryFilters) =>
  h(
    'script',
    {},
    `
    document.addEventListener('DOMContentLoaded', () => {
      const searchInput = document.querySelector('input[name="search"]');
      const sortSelect = document.querySelector('select[name="sort"]');
      let debounceTimer;

      if (searchInput) {
        searchInput.addEventListener('input', (e) => {
          clearTimeout(debounceTimer);
          debounceTimer = setTimeout(() => {
            const params = new URLSearchParams(window.location.search);
            const value = e.target.value.trim();
            if (value) params.set('search', value);
            else params.delete('search');
            window.location.href = '/' + (params.toString() ? '?' + params.toString() : '');
          }, 400);
        });
      }

      if (sortSelect) {
        sortSelect.addEventListener('change', (e) => {
          const params = new URLSearchParams(window.location.search);
          params.set('sort', e.target.value);
          window.location.href = '/' + (params.toString() ? '?' + params.toString() : '');
        });
      }
    });
    `
  )

const renderLightboxScript = () =>
  h(
    'script',
    {},
    `
    document.addEventListener('DOMContentLoaded', () => {
      const images = document.querySelectorAll('.gallery-thumb');
      const overlay = document.getElementById('lightbox-overlay');
      const lbImage = document.getElementById('lightbox-image');
      const lbCaption = document.getElementById('lightbox-caption');
      const lbCounter = document.getElementById('lightbox-counter');
      const prevBtn = document.getElementById('lightbox-prev');
      const nextBtn = document.getElementById('lightbox-next');
      const closeBtn = document.getElementById('lightbox-close');

      let currentIndex = 0;
      const imageData = Array.from(images).map(img => ({ src: img.dataset.full, alt: img.alt }));

      const show = (index) => {
        currentIndex = index;
        lbImage.src = imageData[index].src;
        lbImage.alt = imageData[index].alt;
        lbCaption.textContent = imageData[index].alt;
        lbCounter.textContent = (index + 1) + ' / ' + imageData.length;
        overlay.style.display = 'flex';
        document.body.style.overflow = 'hidden';
      };

      const hide = () => {
        overlay.style.display = 'none';
        document.body.style.overflow = '';
      };

      const prev = () => show((currentIndex - 1 + imageData.length) % imageData.length);
      const next = () => show((currentIndex + 1) % imageData.length);

      images.forEach((img, i) => img.addEventListener('click', () => show(i)));
      closeBtn.addEventListener('click', hide);
      prevBtn.addEventListener('click', prev);
      nextBtn.addEventListener('click', next);
      overlay.addEventListener('click', (e) => { if (e.target === overlay) hide(); });

      document.addEventListener('keydown', (e) => {
        if (overlay.style.display !== 'flex') return;
        if (e.key === 'Escape') hide();
        if (e.key === 'ArrowLeft') prev();
        if (e.key === 'ArrowRight') next();
      });
    });
    `
  )

