import type { GalleryFilters, SortField, SortOrder } from './types'
import { filterProjects, getProject, getAllTags } from './store'
import { renderGalleryPage, renderDetailPage, renderNotFound } from './render'

const parseFilters = (url: URL): GalleryFilters => {
  const search = url.searchParams.get('search') ?? ''
  const tag = url.searchParams.get('tag') ?? null
  const sortParam = url.searchParams.get('sort') ?? 'dateAdded-desc'
  const [sortField, sortOrder] = sortParam.split('-') as [SortField, SortOrder]

  return {
    search,
    tag,
    sortField: sortField === 'title' ? 'title' : 'dateAdded',
    sortOrder: sortOrder === 'asc' ? 'asc' : 'desc',
  }
}

const htmlResponse = (html: string, status = 200): Response =>
  new Response(html, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

export const handleRequest = async (request: Request): Promise<Response> => {
  const url = new URL(request.url)
  const path = url.pathname

  // Gallery index
  if (path === '/' || path === '') {
    const filters = parseFilters(url)
    const [projects, allTags] = await Promise.all([filterProjects(filters), getAllTags()])
    const html = renderGalleryPage(projects, allTags, filters)
    return htmlResponse(html)
  }

  // Project detail
  const detailMatch = path.match(/^\/project\/([a-z0-9-]+)$/)
  if (detailMatch) {
    const project = await getProject(detailMatch[1])
    if (!project) {
      return htmlResponse(renderNotFound(), 404)
    }
    const html = renderDetailPage(project)
    return htmlResponse(html)
  }

  return htmlResponse(renderNotFound(), 404)
}

