import type { Playlist, PlaylistStore, Song } from './types'

const DATA_PATH = `${import.meta.dir}/data/playlists.json`

const generateId = (prefix: string): string =>
  `${prefix}_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`

const readStore = async (): Promise<PlaylistStore> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json()
  }
  return { playlists: [] }
}

const writeStore = async (store: PlaylistStore): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2))
}

export const getPlaylists = async (): Promise<Playlist[]> => {
  const store = await readStore()
  return store.playlists
}

export const getPlaylist = async (id: string): Promise<Playlist | undefined> => {
  const store = await readStore()
  return store.playlists.find((p) => p.id === id)
}

export const createPlaylist = async (name: string, description = ''): Promise<Playlist> => {
  const store = await readStore()
  const now = new Date().toISOString()
  const playlist: Playlist = {
    id: generateId('pl'),
    name,
    description,
    songs: [],
    createdAt: now,
    updatedAt: now,
  }
  store.playlists.push(playlist)
  await writeStore(store)
  return playlist
}

export const deletePlaylist = async (id: string): Promise<boolean> => {
  const store = await readStore()
  const idx = store.playlists.findIndex((p) => p.id === id)
  if (idx === -1) return false
  store.playlists.splice(idx, 1)
  await writeStore(store)
  return true
}

export const addSong = async (
  playlistId: string,
  song: Omit<Song, 'id'>
): Promise<Song | null> => {
  const store = await readStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return null
  const newSong: Song = { ...song, id: generateId('s') }
  playlist.songs.push(newSong)
  playlist.updatedAt = new Date().toISOString()
  await writeStore(store)
  return newSong
}

export const removeSong = async (playlistId: string, songId: string): Promise<boolean> => {
  const store = await readStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return false
  const idx = playlist.songs.findIndex((s) => s.id === songId)
  if (idx === -1) return false
  playlist.songs.splice(idx, 1)
  playlist.updatedAt = new Date().toISOString()
  await writeStore(store)
  return true
}

export const reorderSongs = async (
  playlistId: string,
  songIds: string[]
): Promise<boolean> => {
  const store = await readStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return false
  const songMap = new Map(playlist.songs.map((s) => [s.id, s]))
  const reordered: Song[] = []
  for (const id of songIds) {
    const song = songMap.get(id)
    if (song) reordered.push(song)
  }
  if (reordered.length !== playlist.songs.length) return false
  playlist.songs = reordered
  playlist.updatedAt = new Date().toISOString()
  await writeStore(store)
  return true
}

import type { PlaybackState, RepeatMode, Song } from './types'

const generateShuffleOrder = (length: number): number[] => {
  const order = Array.from({ length }, (_, i) => i)
  for (let i = order.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[order[i], order[j]] = [order[j], order[i]]
  }
  return order
}

export const createPlaybackState = (): PlaybackState => ({
  playlistId: null,
  songIndex: 0,
  isPlaying: false,
  currentTime: 0,
  shuffle: false,
  repeat: 'off',
  shuffleOrder: [],
})

export const startPlaylist = (
  state: PlaybackState,
  playlistId: string,
  songCount: number,
  startIndex = 0
): PlaybackState => ({
  ...state,
  playlistId,
  songIndex: startIndex,
  isPlaying: true,
  currentTime: 0,
  shuffleOrder: state.shuffle ? generateShuffleOrder(songCount) : [],
})

export const togglePlay = (state: PlaybackState): PlaybackState => ({
  ...state,
  isPlaying: !state.isPlaying,
})

export const seekTo = (state: PlaybackState, time: number): PlaybackState => ({
  ...state,
  currentTime: Math.max(0, time),
})

export const getEffectiveIndex = (state: PlaybackState): number => {
  if (state.shuffle && state.shuffleOrder.length > 0) {
    return state.shuffleOrder[state.songIndex] ?? state.songIndex
  }
  return state.songIndex
}

export const skipNext = (state: PlaybackState, songCount: number): PlaybackState => {
  if (songCount === 0) return state

  if (state.repeat === 'one') {
    return { ...state, currentTime: 0, isPlaying: true }
  }

  const nextIndex = state.songIndex + 1
  if (nextIndex >= songCount) {
    if (state.repeat === 'all') {
      return {
        ...state,
        songIndex: 0,
        currentTime: 0,
        isPlaying: true,
        shuffleOrder: state.shuffle ? generateShuffleOrder(songCount) : [],
      }
    }
    return { ...state, isPlaying: false, currentTime: 0 }
  }

  return { ...state, songIndex: nextIndex, currentTime: 0, isPlaying: true }
}

export const skipPrevious = (state: PlaybackState, songCount: number): PlaybackState => {
  if (songCount === 0) return state

  if (state.currentTime > 3) {
    return { ...state, currentTime: 0 }
  }

  const prevIndex = state.songIndex - 1
  if (prevIndex < 0) {
    if (state.repeat === 'all') {
      return { ...state, songIndex: songCount - 1, currentTime: 0 }
    }
    return { ...state, currentTime: 0 }
  }

  return { ...state, songIndex: prevIndex, currentTime: 0 }
}

export const toggleShuffle = (state: PlaybackState, songCount: number): PlaybackState => {
  const newShuffle = !state.shuffle
  return {
    ...state,
    shuffle: newShuffle,
    shuffleOrder: newShuffle ? generateShuffleOrder(songCount) : [],
  }
}

export const cycleRepeat = (state: PlaybackState): PlaybackState => {
  const modes: RepeatMode[] = ['off', 'all', 'one']
  const currentIdx = modes.indexOf(state.repeat)
  const nextMode = modes[(currentIdx + 1) % modes.length]
  return { ...state, repeat: nextMode }
}

export const getCurrentSong = (state: PlaybackState, songs: Song[]): Song | null => {
  if (songs.length === 0) return null
  const idx = getEffectiveIndex(state)
  return songs[idx] ?? null
}

export const formatDuration = (seconds: number): string => {
  const mins = Math.floor(seconds / 60)
  const secs = Math.floor(seconds % 60)
  return `${mins}:${secs.toString().padStart(2, '0')}`
}

export const formatTotalDuration = (songs: { duration: number }[]): string => {
  const total = songs.reduce((sum, s) => sum + s.duration, 0)
  const hrs = Math.floor(total / 3600)
  const mins = Math.floor((total % 3600) / 60)
  if (hrs > 0) return `${hrs} hr ${mins} min`
  return `${mins} min`
}

