export const renderNowPlayingBar = (
  song: Song | null,
  state: PlaybackState
) => {
  if (!song) return h(Fragment, {})

  const progressPercent = song.duration > 0
    ? Math.min(100, (state.currentTime / song.duration) * 100)
    : 0

  const shuffleColor = state.shuffle ? colors.shuffleActive : colors.textMuted
  const repeatColor = state.repeat !== 'off' ? colors.repeatActive : colors.textMuted

  const repeatLabel =
    state.repeat === 'one' ? ICONS.repeatOne :
    ICONS.repeatAll

  return h(
    'div',
    { style: nowPlayingBarStyle },
    // Progress bar
    h(
      'div',
      {
        style: progressBarContainerStyle,
        'p-trigger': JSON.stringify({ click: 'seek-progress' }),
      },
      h(
        'div',
        { style: progressBarBgStyle },
        h('div', {
          style: {
            width: `${progressPercent}%`,
            height: '100%',
            background: colors.progressFill,
            borderRadius: '2px',
            transition: 'width 0.3s linear',
          },
        })
      )
    ),
    // Main bar content
    h(
      'div',
      { style: nowPlayingInnerStyle },
      // Album art
      albumArt(song.albumArtUrl, nowPlayingArtStyle),
      // Song info
      h(
        'div',
        { style: { flex: '1', minWidth: '0' } },
        h('div', {
          style: {
            fontSize: '14px',
            fontWeight: '600',
            whiteSpace: 'nowrap',
            overflow: 'hidden',
            textOverflow: 'ellipsis',
          },
        }, song.title),
        h('div', {
          style: { fontSize: '12px', color: colors.textMuted, marginTop: '2px' },
        }, `${song.artist} — ${song.album}`),
        h('div', {
          style: { fontSize: '11px', color: colors.textMuted, marginTop: '2px' },
        }, `${formatDuration(state.currentTime)} / ${formatDuration(song.duration)}`)
      ),
      // Controls
      h(
        'div',
        { style: controlsStyle },
        h(
          'button',
          {
            style: { ...iconButtonStyle, color: shuffleColor },
            'p-trigger': JSON.stringify({ click: 'toggle-shuffle' }),
            title: `Shuffle: ${state.shuffle ? 'on' : 'off'}`,
          },
          ICONS.shuffle
        ),
        h(
          'button',
          {
            style: iconButtonStyle,
            'p-trigger': JSON.stringify({ click: 'skip-prev' }),
          },
          ICONS.prev
        ),
        h(
          'button',
          {
            style: playButtonStyle,
            'p-trigger': JSON.stringify({ click: 'toggle-play' }),
          },
          state.isPlaying ? ICONS.pause : ICONS.play
        ),
        h(
          'button',
          {
            style: iconButtonStyle,
            'p-trigger': JSON.stringify({ click: 'skip-next' }),
          },
          ICONS.next
        ),
        h(
          'button',
          {
            style: { ...iconButtonStyle, color: repeatColor },
            'p-trigger': JSON.stringify({ click: 'cycle-repeat' }),
            title: `Repeat: ${state.repeat}`,
          },
          repeatLabel
        )
      )
    ),
    // Hidden audio element placeholder
    h('audio', {
      'p-target': 'audio-player',
      preload: 'none',
      style: { display: 'none' },
    })
  )
}

