import { createSSR } from 'plaited'
import type { PlaybackState } from './types'
import {
  getPlaylists,
  getPlaylist,
  createPlaylist,
  deletePlaylist,
  addSong,
  removeSong,
  reorderSongs,
} from './store'
import {
  createPlaybackState,
  startPlaylist,
  togglePlay,
  skipNext,
  skipPrevious,
  toggleShuffle,
  cycleRepeat,
  seekTo,
  getCurrentSong,
} from './playback'
import {
  renderApp,
  renderPlaylistsList,
  renderPlaylistDetail,
  renderNowPlayingBar,
  renderCreatePlaylistModal,
  renderAddSongModal,
} from './ui'

let playbackState: PlaybackState = createPlaybackState()

const ssr = createSSR()

const renderPage = async (
  view: 'list' | 'detail',
  playlistId?: string,
  modal?: 'create-playlist' | 'add-song',
  modalPlaylistId?: string
) => {
  let content
  if (view === 'detail' && playlistId) {
    const playlist = await getPlaylist(playlistId)
    if (playlist) {
      content = renderPlaylistDetail(playlist, playbackState)
    } else {
      content = renderPlaylistsList(await getPlaylists())
    }
  } else {
    content = renderPlaylistsList(await getPlaylists())
  }

  const currentPlaylist = playbackState.playlistId
    ? await getPlaylist(playbackState.playlistId)
    : null
  const currentSong = currentPlaylist
    ? getCurrentSong(playbackState, currentPlaylist.songs)
    : null
  const nowPlayingBar = renderNowPlayingBar(currentSong, playbackState)

  let modalEl = null
  if (modal === 'create-playlist') {
    modalEl = renderCreatePlaylistModal()
  } else if (modal === 'add-song' && modalPlaylistId) {
    modalEl = renderAddSongModal(modalPlaylistId)
  }

  const app = renderApp(content, nowPlayingBar, modalEl)
  return ssr(app)
}

const htmlShell = (body: string) => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Playlist Manager</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #0d1117; color: #e6edf3; }
    button:hover { opacity: 0.85; }
    input:focus { outline: 1px solid #58a6ff; border-color: #58a6ff; }
    [draggable="true"]:active { opacity: 0.6; }
    .drag-over { background: rgba(88, 166, 255, 0.08) !important; }
  </style>
</head>
<body>${body}
<script>
  // Client-side drag-to-reorder
  let dragSrcIndex = null;
  document.addEventListener('dragstart', (e) => {
    const row = e.target.closest('[data-song-id]');
    if (!row) return;
    dragSrcIndex = Number(row.dataset.index);
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', row.dataset.songId);
    row.style.opacity = '0.4';
  });
  document.addEventListener('dragover', (e) => {
    const row = e.target.closest('[data-song-id]');
    if (!row) return;
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
    row.classList.add('drag-over');
  });
  document.addEventListener('dragleave', (e) => {
    const row = e.target.closest('[data-song-id]');
    if (row) row.classList.remove('drag-over');
  });
  document.addEventListener('dragend', (e) => {
    document.querySelectorAll('[data-song-id]').forEach(r => {
      r.style.opacity = '1';
      r.classList.remove('drag-over');
    });
  });
  document.addEventListener('drop', async (e) => {
    e.preventDefault();
    const row = e.target.closest('[data-song-id]');
    if (!row) return;
    row.classList.remove('drag-over');
    const dropIndex = Number(row.dataset.index);
    if (dragSrcIndex === null || dragSrcIndex === dropIndex) return;
    const rows = Array.from(document.querySelectorAll('[data-song-id]'));
    const ids = rows.map(r => r.dataset.songId);
    const [moved] = ids.splice(dragSrcIndex, 1);
    ids.splice(dropIndex, 0, moved);
    const playlistId = window.location.pathname.split('/playlist/')[1];
    if (playlistId) {
      await fetch('/api/reorder/' + playlistId, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ songIds: ids }),
      });
      window.location.reload();
    }
  });

  // Simple client-side navigation and actions
  document.addEventListener('click', async (e) => {
    const btn = e.target.closest('[p-trigger]');
    if (!btn) return;
    const triggers = JSON.parse(btn.getAttribute('p-trigger'));
    const action = triggers.click;
    if (!action) return;

    if (action === 'stop-propagation') { e.stopPropagation(); return; }

    if (action.startsWith('open-playlist--')) {
      const id = action.replace('open-playlist--', '');
      window.location.href = '/playlist/' + id;
      return;
    }
    if (action === 'go-back') {
      window.location.href = '/';
      return;
    }
    if (action === 'show-create-playlist') {
      window.location.href = '/?modal=create-playlist';
      return;
    }
    if (action.startsWith('show-add-song--')) {
      const plId = action.replace('show-add-song--', '');
      window.location.href = '/playlist/' + plId + '?modal=add-song';
      return;
    }
    if (action === 'close-modal') {
      const path = window.location.pathname;
      window.location.href = path;
      return;
    }
    if (action === 'confirm-create-playlist') {
      const name = document.querySelector('[p-target="playlist-name-input"]')?.value || '';
      const desc = document.querySelector('[p-target="playlist-desc-input"]')?.value || '';
      if (!name.trim()) { alert('Name is required'); return; }
      const res = await fetch('/api/playlist', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: name.trim(), description: desc.trim() }),
      });
      const data = await res.json();
      window.location.href = '/playlist/' + data.id;
      return;
    }
    if (action === 'confirm-add-song') {
      const title = document.querySelector('[p-target="song-title-input"]')?.value || '';
      const artist = document.querySelector('[p-target="song-artist-input"]')?.value || '';
      const album = document.querySelector('[p-target="song-album-input"]')?.value || '';
      const dur = document.querySelector('[p-target="song-duration-input"]')?.value || '180';
      const art = document.querySelector('[p-target="song-art-input"]')?.value || '';
      const plId = document.querySelector('[p-target="song-playlist-id"]')?.value || '';
      if (!title.trim() || !artist.trim()) { alert('Title and Artist are required'); return; }
      await fetch('/api/song/' + plId, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          title: title.trim(),
          artist: artist.trim(),
          album: album.trim(),
          duration: parseInt(dur) || 180,
          albumArtUrl: art.trim(),
        }),
      });
      window.location.href = '/playlist/' + plId;
      return;
    }
    if (action.startsWith('remove-song--')) {
      const parts = action.replace('remove-song--', '').split('--');
      const [plId, songId] = parts;
      e.stopPropagation();
      await fetch('/api/song/' + plId + '/' + songId, { method: 'DELETE' });
      window.location.reload();
      return;
    }
    if (action.startsWith('delete-playlist--')) {
      const plId = action.replace('delete-playlist--', '');
      if (!confirm('Delete this playlist?')) return;
      await fetch('/api/playlist/' + plId, { method: 'DELETE' });
      window.location.href = '/';
      return;
    }
    if (action.startsWith('play-song--')) {
      const parts = action.replace('play-song--', '').split('--');
      const [plId, idx] = parts;
      await fetch('/api/playback/start', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ playlistId: plId, songIndex: parseInt(idx) }),
      });
      window.location.reload();
      return;
    }
    if (action === 'toggle-play') {
      await fetch('/api/playback/toggle', { method: 'POST' });
      window.location.reload();
      return;
    }
    if (action === 'skip-next') {
      await fetch('/api/playback/next', { method: 'POST' });
      window.location.reload();
      return;
    }
    if (action === 'skip-prev') {
      await fetch('/api/playback/prev', { method: 'POST' });
      window.location.reload();
      return;
    }
    if (action === 'toggle-shuffle') {
      await fetch('/api/playback/shuffle', { method: 'POST' });
      window.location.reload();
      return;
    }
    if (action === 'cycle-repeat') {
      await fetch('/api/playback/repeat', { method: 'POST' });
      window.location.reload();
      return;
    }
    if (action === 'seek-progress') {
      const container = btn;
      const rect = container.getBoundingClientRect();
      const pct = (e.clientX - rect.left) / rect.width;
      await fetch('/api/playback/seek', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ percent: pct }),
      });
      window.location.reload();
      return;
    }
  });

  // Enter key submits modals
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') {
      const createBtn = document.querySelector('[p-trigger*="confirm-create-playlist"]');
      const addBtn = document.querySelector('[p-trigger*="confirm-add-song"]');
      if (createBtn) createBtn.click();
      else if (addBtn) addBtn.click();
    }
    if (e.key === 'Escape') {
      const path = window.location.pathname;
      window.location.href = path;
    }
  });

  // Simulate playback progress
  setInterval(async () => {
    try {
      const res = await fetch('/api/playback/state');
      const state = await res.json();
      if (state.isPlaying) {
        await fetch('/api/playback/tick', { method: 'POST' });
        // Update progress bar without full reload
        const bar = document.querySelector('[p-target="now-playing-bar"]');
        if (bar) {
          const progDiv = bar.querySelector('[style*="transition"]');
          if (progDiv && state.duration > 0) {
            const pct = Math.min(100, ((state.currentTime + 1) / state.duration) * 100);
            progDiv.style.width = pct + '%';
          }
          const timeEl = bar.querySelectorAll('div');
          timeEl.forEach(el => {
            if (el.textContent && el.textContent.match(/^\\d+:\\d+ \\/ \\d+:\\d+$/)) {
              const t = state.currentTime + 1;
              const m = Math.floor(t / 60);
              const s = Math.floor(t % 60);
              const dm = Math.floor(state.duration / 60);
              const ds = Math.floor(state.duration % 60);
              el.textContent = m + ':' + String(s).padStart(2, '0') + ' / ' + dm + ':' + String(ds).padStart(2, '0');
            }
          });
        }
      }
    } catch (_) {}
  }, 1000);
