const parseUrl = (url: string) => {
  const u = new URL(url, 'http://localhost')
  return { pathname: u.pathname, searchParams: u.searchParams }
}

export const serve = () =>
  Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const { pathname, searchParams } = parseUrl(req.url)
      const method = req.method

      // --- API routes ---

      if (pathname === '/api/playlist' && method === 'POST') {
        const body = await req.json() as { name: string; description?: string }
        const playlist = await createPlaylist(body.name, body.description)
        return Response.json(playlist)
      }

      if (pathname.startsWith('/api/playlist/') && method === 'DELETE') {
        const id = pathname.replace('/api/playlist/', '')
        await deletePlaylist(id)
        return Response.json({ ok: true })
      }

      if (pathname.startsWith('/api/song/') && method === 'POST') {
        const playlistId = pathname.replace('/api/song/', '')
        const body = await req.json()
        const song = await addSong(playlistId, body)
        return Response.json(song)
      }

      if (pathname.startsWith('/api/song/') && method === 'DELETE') {
        const parts = pathname.replace('/api/song/', '').split('/')
        await removeSong(parts[0], parts[1])
        return Response.json({ ok: true })
      }

      if (pathname.startsWith('/api/reorder/') && method === 'POST') {
        const playlistId = pathname.replace('/api/reorder/', '')
        const { songIds } = await req.json() as { songIds: string[] }
        await reorderSongs(playlistId, songIds)
        return Response.json({ ok: true })
      }

      // Playback API
      if (pathname === '/api/playback/start' && method === 'POST') {
        const { playlistId, songIndex } = await req.json() as {
          playlistId: string
          songIndex: number
        }
        const playlist = await getPlaylist(playlistId)
        if (playlist) {
          playbackState = startPlaylist(playbackState, playlistId, playlist.songs.length, songIndex)
        }
        return Response.json({ ok: true })
      }

      if (pathname === '/api/playback/toggle' && method === 'POST') {
        playbackState = togglePlay(playbackState)
        return Response.json({ ok: true })
      }

      if (pathname === '/api/playback/next' && method === 'POST') {
        if (playbackState.playlistId) {
          const pl = await getPlaylist(playbackState.playlistId)
          if (pl) playbackState = skipNext(playbackState, pl.songs.length)
        }
        return Response.json({ ok: true })
      }

      if (pathname === '/api/playback/prev' && method === 'POST') {
        if (playbackState.playlistId) {
          const pl = await getPlaylist(playbackState.playlistId)
          if (pl) playbackState = skipPrevious(playbackState, pl.songs.length)
        }
        return Response.json({ ok: true })
      }

      if (pathname === '/api/playback/shuffle' && method === 'POST') {
        if (playbackState.playlistId) {
          const pl = await getPlaylist(playbackState.playlistId)
          if (pl) playbackState = toggleShuffle(playbackState, pl.songs.length)
        }
        return Response.json({ ok: true })
      }

      if (pathname === '/api/playback/repeat' && method === 'POST') {
        playbackState = cycleRepeat(playbackState)
        return Response.json({ ok: true })
      }

      if (pathname === '/api/playback/seek' && method === 'POST') {
        const { percent } = await req.json() as { percent: number }
        if (playbackState.playlistId) {
          const pl = await getPlaylist(playbackState.playlistId)
          if (pl) {
            const song = getCurrentSong(playbackState, pl.songs)
            if (song) {
              playbackState = seekTo(playbackState, Math.floor(percent * song.duration))
            }
          }
        }
        return Response.json({ ok: true })
      }

      if (pathname === '/api/playback/tick' && method === 'POST') {
        if (playbackState.isPlaying && playbackState.playlistId) {
          const pl = await getPlaylist(playbackState.playlistId)
          if (pl) {
            const song = getCurrentSong(playbackState, pl.songs)
            if (song) {
              const newTime = playbackState.currentTime + 1
              if (newTime >= song.duration) {
                playbackState = skipNext(playbackState, pl.songs.length)
              } else {
                playbackState = { ...playbackState, currentTime: newTime }
              }
            }
          }
        }
        return Response.json({ ok: true })
      }

      if (pathname === '/api/playback/state' && method === 'GET') {
        let duration = 0
        if (playbackState.playlistId) {
          const pl = await getPlaylist(playbackState.playlistId)
          if (pl) {
            const song = getCurrentSong(playbackState, pl.songs)
            if (song) duration = song.duration
          }
        }
        return Response.json({ ...playbackState, duration })
      }

      // --- Page routes ---

      if (pathname.startsWith('/playlist/')) {
        const id = pathname.replace('/playlist/', '')
        const modal = searchParams.get('modal') as 'add-song' | null
        const html = await renderPage('detail', id, modal ?? undefined, id)
        return new Response(htmlShell(html), {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      // Default: playlists list
      const modal = searchParams.get('modal') as 'create-playlist' | null
      const html = await renderPage('list', undefined, modal ?? undefined)
      return new Response(htmlShell(html), {
        headers: { 'Content-Type': 'text/html' },
      })
    },
  })

