{
  "name": "@node/statistics-calculator",
  "version": "1.0.0",
  "description": "Statistical analysis calculator with box plots, histograms, and multi-dataset comparison",
  "main": "src/index.ts",
  "modnet": {
    "contentType": "science",
    "structure": "form",
    "mechanics": ["chart", "sort", "filter"],
