export type Dataset = {
  name: string
  values: number[]
}

export type Stats = {
  count: number
  mean: number
  median: number
  mode: number[]
  standardDeviation: number
  variance: number
  min: number
  max: number
  range: number
  q1: number
  q3: number
  iqr: number
}

const sorted = (arr: number[]): number[] => [...arr].sort((a, b) => a - b)

const sum = (arr: number[]): number => arr.reduce((acc, v) => acc + v, 0)

const mean = (arr: number[]): number => sum(arr) / arr.length

const median = (arr: number[]): number => {
  const s = sorted(arr)
  const mid = Math.floor(s.length / 2)
  return s.length % 2 === 0 ? (s[mid - 1] + s[mid]) / 2 : s[mid]
}

const quartile = (arr: number[], q: 0.25 | 0.75): number => {
  const s = sorted(arr)
  const pos = (s.length - 1) * q
  const base = Math.floor(pos)
  const rest = pos - base
  if (s[base + 1] !== undefined) {
    return s[base] + rest * (s[base + 1] - s[base])
  }
  return s[base]
}

const mode = (arr: number[]): number[] => {
  const freq = new Map<number, number>()
  for (const v of arr) {
    freq.set(v, (freq.get(v) ?? 0) + 1)
  }
  const maxFreq = Math.max(...freq.values())
  if (maxFreq === 1) return [] // no mode when all values appear once
  const modes: number[] = []
  for (const [val, count] of freq) {
    if (count === maxFreq) modes.push(val)
  }
  return sorted(modes)
}

const variance = (arr: number[]): number => {
  const m = mean(arr)
  return sum(arr.map((v) => (v - m) ** 2)) / arr.length
}

export const computeStats = (values: number[]): Stats => {
  if (values.length === 0) {
    return {
      count: 0,
      mean: 0,
      median: 0,
      mode: [],
      standardDeviation: 0,
      variance: 0,
      min: 0,
      max: 0,
      range: 0,
      q1: 0,
      q3: 0,
      iqr: 0,
    }
  }
  const s = sorted(values)
  const v = variance(values)
  const q1Val = quartile(values, 0.25)
  const q3Val = quartile(values, 0.75)
  return {
    count: values.length,
    mean: mean(values),
    median: median(values),
    mode: mode(values),
    standardDeviation: Math.sqrt(v),
    variance: v,
    min: s[0],
    max: s[s.length - 1],
    range: s[s.length - 1] - s[0],
    q1: q1Val,
    q3: q3Val,
    iqr: q3Val - q1Val,
  }
}

export const parseInput = (input: string): number[] => {
  const trimmed = input.trim()
  // Try JSON array first
  if (trimmed.startsWith('[')) {
    try {
      const parsed = JSON.parse(trimmed)
      if (Array.isArray(parsed)) {
        return parsed.filter((v): v is number => typeof v === 'number' && !isNaN(v))
      }
    } catch {
      // fall through to CSV parsing
    }
  }
  // CSV parsing
  return trimmed
    .split(',')
    .map((s) => s.trim())
    .filter((s) => s.length > 0)
    .map(Number)
    .filter((n) => !isNaN(n))
}

export const formatNumber = (n: number): string => {
  if (Number.isInteger(n)) return n.toString()
  return n.toFixed(4).replace(/0+$/, '').replace(/\.$/, '')
}

import { h, Fragment } from 'plaited'
import { type Dataset, type Stats, computeStats, formatNumber } from './stats.js'

const COLORS = ['#4C72B0', '#DD8452', '#55A868', '#C44E52', '#8172B3', '#937860', '#DA8BC3', '#8C8C8C']

const colorFor = (index: number): string => COLORS[index % COLORS.length]

// --- Summary Table ---

const statLabels: { key: keyof Stats; label: string }[] = [
  { key: 'count', label: 'Count' },
  { key: 'mean', label: 'Mean' },
  { key: 'median', label: 'Median' },
  { key: 'mode', label: 'Mode' },
  { key: 'standardDeviation', label: 'Std Dev' },
  { key: 'variance', label: 'Variance' },
  { key: 'min', label: 'Min' },
  { key: 'max', label: 'Max' },
  { key: 'range', label: 'Range' },
  { key: 'q1', label: 'Q1' },
  { key: 'q3', label: 'Q3' },
  { key: 'iqr', label: 'IQR' },
]

const formatStatValue = (value: number | number[]): string => {
  if (Array.isArray(value)) {
    return value.length === 0 ? 'N/A' : value.map(formatNumber).join(', ')
  }
  return formatNumber(value)
}

export const renderSummaryTable = (datasets: Dataset[]): string => {
  const allStats = datasets.map((ds) => ({
    name: ds.name,
    stats: computeStats(ds.values),
  }))

  const headerCells = [
    h('th', { style: 'padding:8px 12px;text-align:left;border-bottom:2px solid #ddd;background:#f8f9fa;position:sticky;left:0;z-index:1' }, 'Statistic'),
    ...allStats.map((ds, i) =>
      h('th', { style: `padding:8px 12px;text-align:right;border-bottom:2px solid #ddd;background:#f8f9fa;color:${colorFor(i)}` }, ds.name)
    ),
  ]

  const rows = statLabels.map(({ key, label }) =>
    h('tr', {},
      h('td', { style: 'padding:6px 12px;font-weight:600;border-bottom:1px solid #eee;background:#fafafa;position:sticky;left:0' }, label),
      ...allStats.map((ds) =>
        h('td', { style: 'padding:6px 12px;text-align:right;border-bottom:1px solid #eee;font-variant-numeric:tabular-nums' },
          formatStatValue(ds.stats[key])
        )
      )
