    )
  )
}

// --- Box Plot ---

const BOX_PLOT_WIDTH = 600
const BOX_PLOT_HEIGHT = 200
const BOX_PLOT_PADDING = { top: 30, right: 40, bottom: 40, left: 60 }

export const renderBoxPlot = (datasets: Dataset[]): string => {
  const allValues = datasets.flatMap((ds) => ds.values)
  if (allValues.length === 0) return h('p', {}, 'No data to display')

  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)
  const padding = (globalMax - globalMin) * 0.05 || 1
  const scaleMin = globalMin - padding
  const scaleMax = globalMax + padding

  const plotW = BOX_PLOT_WIDTH - BOX_PLOT_PADDING.left - BOX_PLOT_PADDING.right
  const plotH = BOX_PLOT_HEIGHT - BOX_PLOT_PADDING.top - BOX_PLOT_PADDING.bottom
  const rowHeight = plotH / datasets.length

  const xScale = (v: number): number =>
    BOX_PLOT_PADDING.left + ((v - scaleMin) / (scaleMax - scaleMin)) * plotW

  // Axis ticks
  const tickCount = 6
  const tickStep = (scaleMax - scaleMin) / (tickCount - 1)
  const ticks = Array.from({ length: tickCount }, (_, i) => scaleMin + i * tickStep)

  const tickLines = ticks.map((t) => {
    const x = xScale(t)
    return h('g', {},
      h('line', { x1: String(x), y1: String(BOX_PLOT_PADDING.top), x2: String(x), y2: String(BOX_PLOT_PADDING.top + plotH), stroke: '#eee', 'stroke-width': '1' }),
      h('text', { x: String(x), y: String(BOX_PLOT_PADDING.top + plotH + 16), 'text-anchor': 'middle', 'font-size': '11', fill: '#666' }, formatNumber(t))
    )
  })

  const boxes = datasets.map((ds, i) => {
    const stats = computeStats(ds.values)
    const yCenter = BOX_PLOT_PADDING.top + i * rowHeight + rowHeight / 2
    const boxH = rowHeight * 0.6
    const yTop = yCenter - boxH / 2
    const color = colorFor(i)

    // Whisker bounds (clamped to 1.5*IQR)
    const lowerWhisker = Math.max(stats.min, stats.q1 - 1.5 * stats.iqr)
    const upperWhisker = Math.min(stats.max, stats.q3 + 1.5 * stats.iqr)

    // Outliers
    const outliers = ds.values.filter((v) => v < lowerWhisker || v > upperWhisker)

    return h('g', {},
      // Label
      h('text', { x: String(BOX_PLOT_PADDING.left - 8), y: String(yCenter + 4), 'text-anchor': 'end', 'font-size': '12', fill: color, 'font-weight': '600' }, ds.name),
      // Lower whisker line
      h('line', { x1: String(xScale(lowerWhisker)), y1: String(yCenter), x2: String(xScale(stats.q1)), y2: String(yCenter), stroke: color, 'stroke-width': '2' }),
      // Upper whisker line
      h('line', { x1: String(xScale(stats.q3)), y1: String(yCenter), x2: String(xScale(upperWhisker)), y2: String(yCenter), stroke: color, 'stroke-width': '2' }),
      // Lower whisker cap
      h('line', { x1: String(xScale(lowerWhisker)), y1: String(yTop), x2: String(xScale(lowerWhisker)), y2: String(yTop + boxH), stroke: color, 'stroke-width': '2' }),
      // Upper whisker cap
      h('line', { x1: String(xScale(upperWhisker)), y1: String(yTop), x2: String(xScale(upperWhisker)), y2: String(yTop + boxH), stroke: color, 'stroke-width': '2' }),
      // Box
      h('rect', {
        x: String(xScale(stats.q1)),
        y: String(yTop),
        width: String(xScale(stats.q3) - xScale(stats.q1)),
        height: String(boxH),
        fill: color,
        'fill-opacity': '0.25',
        stroke: color,
        'stroke-width': '2',
      }),
      // Median line
      h('line', { x1: String(xScale(stats.median)), y1: String(yTop), x2: String(xScale(stats.median)), y2: String(yTop + boxH), stroke: color, 'stroke-width': '3' }),
      // Outliers
      ...outliers.map((v) =>
        h('circle', { cx: String(xScale(v)), cy: String(yCenter), r: '3', fill: 'none', stroke: color, 'stroke-width': '1.5' })
      )
    )
  })

  return h('div', { style: 'margin:16px 0' },
    h('h3', { style: 'font-family:system-ui,sans-serif;font-size:16px;margin-bottom:8px' }, 'Box Plot'),
    h('svg', { width: String(BOX_PLOT_WIDTH), height: String(BOX_PLOT_HEIGHT), viewBox: `0 0 ${BOX_PLOT_WIDTH} ${BOX_PLOT_HEIGHT}`, style: 'font-family:system-ui,sans-serif;background:#fff;border:1px solid #eee;border-radius:4px' },
      ...tickLines,
      ...boxes
    )
  )
}

// --- Histogram ---

const HIST_WIDTH = 600
const HIST_HEIGHT = 280
const HIST_PADDING = { top: 30, right: 20, bottom: 50, left: 50 }
const BIN_COUNT = 15

const buildBins = (values: number[], min: number, max: number, count: number): number[] => {
  const binWidth = (max - min) / count
  const bins = new Array(count).fill(0) as number[]
  for (const v of values) {
    let idx = Math.floor((v - min) / binWidth)
    if (idx >= count) idx = count - 1
    if (idx < 0) idx = 0
    bins[idx]++
  }
  return bins
}

export const renderHistogram = (datasets: Dataset[]): string => {
  const allValues = datasets.flatMap((ds) => ds.values)
  if (allValues.length === 0) return h('p', {}, 'No data to display')

  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)
  const dataRange = globalMax - globalMin || 1

  const plotW = HIST_WIDTH - HIST_PADDING.left - HIST_PADDING.right
  const plotH = HIST_HEIGHT - HIST_PADDING.top - HIST_PADDING.bottom
  const binWidth = plotW / BIN_COUNT

  const allBins = datasets.map((ds) => buildBins(ds.values, globalMin, globalMax, BIN_COUNT))
  const maxBinCount = Math.max(...allBins.flat(), 1)

  const xScale = (bin: number): number => HIST_PADDING.left + bin * binWidth
  const yScale = (count: number): number => HIST_PADDING.top + plotH - (count / maxBinCount) * plotH

  // X-axis ticks
  const xTickCount = Math.min(BIN_COUNT + 1, 8)
  const xTickStep = BIN_COUNT / (xTickCount - 1)
  const xTicks = Array.from({ length: xTickCount }, (_, i) => {
    const bin = Math.round(i * xTickStep)
    const val = globalMin + (bin / BIN_COUNT) * dataRange
    return { bin, val }
  })

  // Y-axis ticks
  const yTickCount = 5
  const yTickStep = maxBinCount / (yTickCount - 1)
  const yTicks = Array.from({ length: yTickCount }, (_, i) => Math.round(i * yTickStep))

  const barGroupWidth = binWidth / datasets.length

  const bars = allBins.flatMap((bins, dsIdx) =>
    bins.map((count, binIdx) => {
      if (count === 0) return ''
      const x = xScale(binIdx) + dsIdx * barGroupWidth
      const y = yScale(count)
      const barH = plotH - (y - HIST_PADDING.top)
      return h('rect', {
        x: String(x + 1),
        y: String(y),
        width: String(barGroupWidth - 2),
        height: String(barH),
        fill: colorFor(dsIdx),
        'fill-opacity': '0.6',
        stroke: colorFor(dsIdx),
        'stroke-width': '1',
      })
    })
  )

  const xAxisTicks = xTicks.map(({ bin, val }) =>
    h('g', {},
      h('line', { x1: String(xScale(bin)), y1: String(HIST_PADDING.top + plotH), x2: String(xScale(bin)), y2: String(HIST_PADDING.top + plotH + 6), stroke: '#999', 'stroke-width': '1' }),
      h('text', { x: String(xScale(bin)), y: String(HIST_PADDING.top + plotH + 20), 'text-anchor': 'middle', 'font-size': '11', fill: '#666' }, formatNumber(val))
    )
  )

  const yAxisTicks = yTicks.map((count) =>
    h('g', {},
      h('line', { x1: String(HIST_PADDING.left - 6), y1: String(yScale(count)), x2: String(HIST_PADDING.left), y2: String(yScale(count)), stroke: '#999', 'stroke-width': '1' }),
      h('line', { x1: String(HIST_PADDING.left), y1: String(yScale(count)), x2: String(HIST_PADDING.left + plotW), y2: String(yScale(count)), stroke: '#f0f0f0', 'stroke-width': '1' }),
      h('text', { x: String(HIST_PADDING.left - 10), y: String(yScale(count) + 4), 'text-anchor': 'end', 'font-size': '11', fill: '#666' }, String(count))
    )
  )

  // Legend
  const legend = datasets.map((ds, i) =>
    h('g', { transform: `translate(${HIST_PADDING.left + i * 120}, ${HIST_HEIGHT - 12})` },
      h('rect', { x: '0', y: '-8', width: '12', height: '12', fill: colorFor(i), 'fill-opacity': '0.6' }),
      h('text', { x: '16', y: '2', 'font-size': '11', fill: '#333' }, ds.name)
    )
  )

  return h('div', { style: 'margin:16px 0' },
    h('h3', { style: 'font-family:system-ui,sans-serif;font-size:16px;margin-bottom:8px' }, 'Histogram'),
    h('svg', { width: String(HIST_WIDTH), height: String(HIST_HEIGHT), viewBox: `0 0 ${HIST_WIDTH} ${HIST_HEIGHT}`, style: 'font-family:system-ui,sans-serif;background:#fff;border:1px solid #eee;border-radius:4px' },
      // Axes
      h('line', { x1: String(HIST_PADDING.left), y1: String(HIST_PADDING.top), x2: String(HIST_PADDING.left), y2: String(HIST_PADDING.top + plotH), stroke: '#ccc', 'stroke-width': '1' }),
      h('line', { x1: String(HIST_PADDING.left), y1: String(HIST_PADDING.top + plotH), x2: String(HIST_PADDING.left + plotW), y2: String(HIST_PADDING.top + plotH), stroke: '#ccc', 'stroke-width': '1' }),
      ...yAxisTicks,
      ...xAxisTicks,
      ...bars,
      ...legend
    )
  )
}

