export const renderPage = (datasets: Dataset[]): string => {
  const formHtml = renderForm()

  if (datasets.length === 0) {
    return h('div', { style: 'max-width:800px;margin:0 auto;padding:20px' },
      formHtml,
      h('p', { style: 'font-family:system-ui,sans-serif;color:#888;margin-top:20px' },
