    renderBoxPlot(datasets),
    renderHistogram(datasets)
  )
}

import { type Dataset, parseInput, computeStats, formatNumber } from './stats.js'
import { renderPage, renderSummaryTable, renderBoxPlot, renderHistogram } from './render.js'

const DATA_PATH = './data/datasets.json'

type StoredData = {
  datasets: Record<string, number[]>
}

const loadDatasets = async (): Promise<Dataset[]> => {
  try {
    const file = Bun.file(DATA_PATH)
    const data: StoredData = await file.json()
    return Object.entries(data.datasets).map(([name, values]) => ({ name, values }))
  } catch {
    return []
  }
}

const saveDatasets = async (datasets: Dataset[]): Promise<void> => {
  const data: StoredData = {
    datasets: Object.fromEntries(datasets.map((ds) => [ds.name, ds.values])),
  }
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

export const addDataset = async (name: string, input: string): Promise<Dataset[]> => {
  const values = parseInput(input)
  if (values.length === 0) {
    throw new Error('No valid numbers found in input')
  }
  const datasets = await loadDatasets()
  const existing = datasets.findIndex((ds) => ds.name === name)
  if (existing >= 0) {
    datasets[existing] = { name, values }
  } else {
    datasets.push({ name, values })
  }
  await saveDatasets(datasets)
  return datasets
}

export const removeDataset = async (name: string): Promise<Dataset[]> => {
  const datasets = await loadDatasets()
  const filtered = datasets.filter((ds) => ds.name !== name)
  await saveDatasets(filtered)
  return filtered
}

export const clearAllDatasets = async (): Promise<Dataset[]> => {
  await saveDatasets([])
  return []
}

export const getDatasets = async (): Promise<Dataset[]> => {
  return loadDatasets()
}

export const getStatsForDataset = async (name: string): Promise<ReturnType<typeof computeStats> | null> => {
  const datasets = await loadDatasets()
  const ds = datasets.find((d) => d.name === name)
  if (!ds) return null
  return computeStats(ds.values)
}

export const render = async (): Promise<string> => {
  const datasets = await loadDatasets()
  return renderPage(datasets)
}

// CLI entry point
const main = async () => {
  const args = process.argv.slice(2)
  const command = args[0]

  if (command === 'add' && args.length >= 3) {
    const name = args[1]
    const input = args.slice(2).join(' ')
    const datasets = await addDataset(name, input)
    const stats = computeStats(datasets.find((ds) => ds.name === name)!.values)
    console.log(`\nDataset "${name}" added (${stats.count} values)\n`)
    console.log(`  Mean:    ${formatNumber(stats.mean)}`)
    console.log(`  Median:  ${formatNumber(stats.median)}`)
    console.log(`  Mode:    ${stats.mode.length ? stats.mode.map(formatNumber).join(', ') : 'N/A'}`)
    console.log(`  Std Dev: ${formatNumber(stats.standardDeviation)}`)
    console.log(`  Var:     ${formatNumber(stats.variance)}`)
    console.log(`  Min:     ${formatNumber(stats.min)}`)
    console.log(`  Max:     ${formatNumber(stats.max)}`)
    console.log(`  Range:   ${formatNumber(stats.range)}`)
    console.log(`  Q1:      ${formatNumber(stats.q1)}`)
    console.log(`  Q3:      ${formatNumber(stats.q3)}`)
    console.log(`  IQR:     ${formatNumber(stats.iqr)}`)
    return
  }

  if (command === 'remove' && args[1]) {
    await removeDataset(args[1])
    console.log(`Dataset "${args[1]}" removed.`)
    return
  }

  if (command === 'clear') {
    await clearAllDatasets()
    console.log('All datasets cleared.')
    return
  }

  if (command === 'list') {
    const datasets = await loadDatasets()
    if (datasets.length === 0) {
      console.log('No datasets stored.')
      return
    }
    for (const ds of datasets) {
      console.log(`  ${ds.name}: ${ds.values.length} values`)
    }
    return
  }

  if (command === 'render') {
    const html = await render()
    console.log(html)
    return
  }

  if (command === 'compare') {
    const datasets = await loadDatasets()
    if (datasets.length === 0) {
      console.log('No datasets to compare. Add datasets first.')
      return
    }

    const allStats = datasets.map((ds) => ({
      name: ds.name,
      stats: computeStats(ds.values),
    }))

    // Header
    const nameWidth = 10
    const colWidth = 14
    const header = 'Statistic'.padEnd(nameWidth) + allStats.map((s) => s.name.padStart(colWidth)).join('')
    console.log(`\n${header}`)
    console.log('-'.repeat(header.length))

    const rows: { label: string; key: keyof ReturnType<typeof computeStats> }[] = [
      { label: 'Count', key: 'count' },
      { label: 'Mean', key: 'mean' },
      { label: 'Median', key: 'median' },
      { label: 'Mode', key: 'mode' },
      { label: 'Std Dev', key: 'standardDeviation' },
      { label: 'Variance', key: 'variance' },
      { label: 'Min', key: 'min' },
      { label: 'Max', key: 'max' },
      { label: 'Range', key: 'range' },
      { label: 'Q1', key: 'q1' },
      { label: 'Q3', key: 'q3' },
      { label: 'IQR', key: 'iqr' },
    ]

    for (const row of rows) {
      const label = row.label.padEnd(nameWidth)
      const vals = allStats.map((s) => {
        const v = s.stats[row.key]
        if (Array.isArray(v)) return (v.length === 0 ? 'N/A' : v.map(formatNumber).join(',')).padStart(colWidth)
        return formatNumber(v).padStart(colWidth)
      }).join('')
      console.log(`${label}${vals}`)
    }
    console.log()
    return
  }

  console.log('Statistics Calculator')
  console.log('')
  console.log('Usage:')
  console.log('  bun run src/index.ts add <name> <values>    Add a dataset (CSV or JSON array)')
  console.log('  bun run src/index.ts remove <name>          Remove a dataset')
  console.log('  bun run src/index.ts clear                  Clear all datasets')
  console.log('  bun run src/index.ts list                   List all datasets')
  console.log('  bun run src/index.ts compare                Compare all datasets side by side')
  console.log('  bun run src/index.ts render                 Render HTML output')
}

main().catch(console.error)
